with patch(id,prompt,explanation,explanation_ku,explanation_tr,correct_option) as (values
('00077c1b-1d22-4524-9990-389235f07c7f', 'Di "Mem û Zîn" de, ji ber kîjan astengiyê du evîndar nikarin hev bibînin?', 'Mem û Zîn ji ber ku fesad Beko (Bekir) mudaxeleyî hev kir, nikarin hev bibînin.', 'Mem û Zîn ji ber ku fesad Beko (Bekir) mudaxeleyî hev kir, nikarin hev bibînin.', 'Mem ile Zîn, araya giren fesatçı Beko (Bekir) yüzünden kavuşamaz.', 'C'),
('001c7db1-fbc0-4fe5-bb72-366728ab8d26', 'Di Kurmancî de wateya "şîr" çi ye?', '"Şîr" bi Tirkî tê wateya "süt".', '"Şîr" bi Tirkî tê wateya "süt".', null, 'D'),
('001e8029-0c64-4ea0-b6a0-f1c53fdbc559', 'Sernavên mîna "Pîr, mîr, feqî, mela" çi destnîşan dikin?', 'Ev sernav rolên sosyo-dînî di civaka kevneşopî ya kurdî de nîşan didin.', 'Ev sernav rolên sosyo-dînî di civaka kevneşopî ya kurdî de nîşan didin.', 'Bu unvanlar, geleneksel Kürt toplumundaki toplumsal-dinî rolleri gösterir.', 'A'),
('00498287-bc3e-4360-b1ca-9bc8d89a40c7', 'Di Kurmancî de wateya "bapîr" çi ye?', '"Bapîr" bi Tirkî tê wateya "dede".', '"Bapîr" bi Tirkî tê wateya "dede".', null, 'C'),
('00c1eade-f056-40ec-90f1-fa085a1dcc71', '"Midyad" navê kurdî yê kîjan wargehê ye?', '"Midyad" navê kurdiya Midyada Mêrdînê ye.', '"Midyad" navê kurdiya Midyada Mêrdînê ye.', '"Midyad", Mardin''e bağlı Midyat''ın Kürtçe adıdır.', 'A'),
('010432dc-5af7-4755-9703-9f32ecff34aa', '"Kilam, stran ve lawik" hevpar çi ye?', 'Kilam, stran û lawik cureyên melodîk ên kevneşopiya kurdî ya devkî-mûzîk in.', 'Kilam, stran û lawik cureyên melodîk ên kevneşopiya kurdî ya devkî-mûzîk in.', 'Kilam, stran ve lawik, Kürt sözlü-müzikal geleneğinin ezgi türleridir.', 'B'),
('0149405d-49a2-4814-be58-99fa64f4784e', 'Çemê Munzur di kîjan bajarî re derbas dibe?', 'Çemê Mûnzûrê di Dersimê (Tuncelî) re derbas dibe.', 'Çemê Mûnzûrê di Dersimê (Tuncelî) re derbas dibe.', 'Munzur Nehri, Dersim (Tunceli) içinden akar.', 'A'),
('017a9684-ac4f-4849-8900-3c3eda0c4251', '"Pêkenok" çi ne?', '"pêkenok" çîrokeke kurt e, yanî henek e, ji bo mebestên mîzahî ye.', '"pêkenok" çîrokeke kurt e, yanî henek e, ji bo mebestên mîzahî ye.', '"pêkenok" güldürü amaçlı kısa anlatı, yani fıkradır.', 'A'),
('017b3239-d71d-4add-ade3-2d43a147818a', 'Peyva "nav" bi Tirkî tê wateya "söz".', '"nav" tê wateya "ad/isim"; "peyiv" tê wateya "söz".', '"nav" tê wateya "ad/isim"; "peyiv" tê wateya "söz".', '"nav" "ad/isim" demektir; "peyiv" ise "söz" anlamına gelir.', 'B'),
('01cc9ca8-e91e-4ca6-b2ca-3cd175ce9c2f', 'Di kîjan serpêhatiya siyasî ya kurda ya kurt de, Mistefa Barzanî di sala 1946an de wek fermandarekî leşkerî derket pêş?', 'Britannica diyar dike ku Mistefa Barzanî di nav artêşa Komara Mehabadê de wek fermandarekî bilind bûye.', 'Britannica diyar dike ku Mistefa Barzanî di nav artêşa Komara Mehabadê de wek fermandarekî bilind bûye.', 'Britannica, Mustafa Barzani’nin Mahabad Cumhuriyeti ordusunda komutan olarak öne çıktığını belirtir.', 'A'),
('0217c1d3-313e-47d8-8c7b-7a1da32a3c62', 'Peyva "Newroz" ji kîjan du peyvan pêk tê?', 'Newroz ji peyvên "nû" (nû) û "roj" (roj) pêk tê: roja nû.', 'Newroz ji peyvên "nû" (nû) û "roj" (roj) pêk tê: roja nû.', 'Newroz, "nû" (yeni) ve "roj" (gün) sözcüklerinden oluşur: yeni gün.', 'C'),
('023135e5-d695-4d53-9811-ad37b3954f7e', 'Mîrnişîna Baban herî zêde wekî mîrnişîna kurdî ya kîjan bajarî tê binavkirin?', 'Mîrnişîna Baban bi taybetî li derdora Silêmaniyê wek mîrnişîna kurdan tê naskirin.', 'Mîrnişîna Baban bi taybetî li derdora Silêmaniyê wek mîrnişîna kurdan tê naskirin.', 'Baban Emirliği, özellikle Süleymaniye çevresindeki Kürt emirliği olarak bilinir.', 'A'),
('0233bfd8-1393-42d4-8c61-bc9b8480bf65', 'Di Kurmancî de "sed" kîjan hejmar e?', '"Sed" bi Tirkî tê wateya "yüz".', '"Sed" bi Tirkî tê wateya "yüz".', null, 'A'),
('02615bb4-a188-401a-a5e2-01d49d1734b4', 'Di kevneşopiya Dengbêjiyê de performans çawa ye?', 'Dengbêjler bi giştî bê enstrûman, bi awazên ku ji îprovîzasyonê re vekirî derdikevin pêş.', 'Dengbêjler bi giştî bê enstrûman, bi awazên ku ji îprovîzasyonê re vekirî derdikevin pêş.', 'Dengbêjler genellikle enstrümansız, doğaçlamaya açık ezgilerle icra eder.', 'C'),
('027b9d22-cf28-4718-bf26-289cb783fef6', 'Wateya peyva "Hawar" çi ye?', '"Hawar" tê wateya tengahiyê / bang; Kovar di heman demê de vê navê xwe jî weke bangekê li ser ziman girtiye.', '"Hawar" tê wateya tengahiyê / bang; Kovar di heman demê de vê navê xwe jî weke bangekê li ser ziman girtiye.', '"Hawar" imdat/çağrı anlamına gelir; dergi de bu adı dile dikkat çağrısı olarak taşır.', 'C'),
('027f70f8-e269-452e-b2c4-20da03c976fa', 'Kurdî bi şaxê hind-îranî yê kîjan malbata zimanên sereke ve girêdayî ye?', 'Kurdî di nav zimanên rojavayî yên îranî de di şaxê hind-îranî/îranî yên malbata zimanên hind-ewropî de tê hesibandin.', 'Kurdî di nav zimanên rojavayî yên îranî de di şaxê hind-îranî/îranî yên malbata zimanên hind-ewropî de tê hesibandin.', 'Kürtçe, Hint-Avrupa dil ailesinin Hint-İran/İrani kolundaki Batı İran dilleri içinde değerlendirilir.', 'A'),
('027fb397-97c3-4a53-ab82-9a0677d9fa09', 'Di Kurmancî de peyva "kaxiz" bi Tirkî çi ye?', 'Peyva "kaxiz" tê wateya "kağıt".', 'Peyva "kaxiz" tê wateya "kağıt".', '"kaxiz" kelimesi "kağıt" anlamına gelir.', 'C'),
('0293833b-a17e-46d4-b2c0-e149d46cad34', 'Peyva "ziman" bi Tirkî tê wateya "okul".', 'Peyva "ziman" tê wateya "dil".', 'Peyva "ziman" tê wateya "dil".', '"ziman" kelimesi "dil" demektir.', 'B'),
('02bb8b09-dc81-45eb-b74a-b4f8cca0e9f3', 'Di Kurmancî de wateya "mar" çi ye?', '"Mar" bi Tirkî tê wateya "yılan".', '"Mar" bi Tirkî tê wateya "yılan".', null, 'D'),
('0313b1eb-bdb1-4977-8e3a-55949f2f1fd8', 'Dîwana Melayê Cizîrî bi kîjan zimanî hatiye nivîsandin?', 'Melayê Cizîrî divanını Kurmancî (Kürtçe) yazmıştır.', null, null, 'C'),
('032b96d9-af6d-4614-9ce4-2a9030f1a10c', 'Kovara "Hawar" çima ji bo çanda kurdî girîng e?', 'Hawar girîng e ji ber ku wî alfabeya kurdî ya latînî û xebatên zimanî yên latînî belav kir.', 'Hawar girîng e ji ber ku wî alfabeya kurdî ya latînî û xebatên zimanî yên latînî belav kir.', 'Hawar, Latin temelli Kürt alfabesi ve dil çalışmalarını yaygınlaştırdığı için önemlidir.', 'B'),
('0379c63b-59c6-466f-adae-5d3e4fda1297', 'Di Kurmancî de peyva "rûniştin" bi Tirkî çi ye?', 'Peyva "rûniştin" tê wateya "oturmak".', 'Peyva "rûniştin" tê wateya "oturmak".', '"rûniştin" kelimesi "oturmak" anlamına gelir.', 'C'),
('03938e58-3072-40e9-b27e-2e7c3d361eae', 'Di çanda Kurdî de dengbêj herî zêde bi kîjan qadê re têkildar e?', 'dengbêjî di çanda kurdî de di çarçoveya çanda devkî de tê nirxandin.', 'dengbêjî di çanda kurdî de di çarçoveya çanda devkî de tê nirxandin.', 'dengbêj, Kürt kültüründe sözlü kültür bağlamında değerlendirilir.', 'B'),
('03c0215e-f593-46e9-902e-01764e80798c', 'Kîjan amûr di dema Govendê (halay) de rîtma bingehîn dide?', 'Di Govendê de defê (dahol) rîtma bingehîn dide; Bi gelemperî bi zurna re tê.', 'Di Govendê de defê (dahol) rîtma bingehîn dide; Bi gelemperî bi zurna re tê.', 'Govend''de temel ritmi davul (dahol) verir; ona genelde zurna eşlik eder.', 'A'),
('041054f1-81b7-48f7-959d-1bb73dc2aaa8', 'Kurmancî bi piranî di kîjan sîstema nivîsandinê de tê nivîsandin?', 'Kurmancî bi alfabeya Hawarê ya latînî belav bûye, nemaze di çarçeweya Tirkiye û Sûriyê de.', 'Kurmancî bi alfabeya Hawarê ya latînî belav bûye, nemaze di çarçeweya Tirkiye û Sûriyê de.', 'Kurmancî, özellikle Türkiye ve Suriye bağlamında Latin temelli Hawar alfabesiyle yaygınlaşmıştır.', 'A'),
('041adaa8-654e-4de9-8211-14db5bc647c1', 'Celadet Alî Bedirxan di warê rêzimanê de çi amade kir?', 'Celadet Alî Bedirxan, Kurmancî gramerine dair temel çalışmalar hazırlamıştır.', null, null, 'A'),
('043683fc-94f7-424c-af91-35f52022f658', '"Riha" navê kurdî yê kîjan bajarî ye?', '"Riha" navê kurdî yê bajarê Şanliurfayê ye.', '"Riha" navê kurdî yê bajarê Şanliurfayê ye.', '"Riha", Şanlıurfa şehrinin Kürtçe adıdır.', 'C'),
('0436ca0e-57b1-429c-8d32-be5813337993', 'Çîroka "Mem û Zîn" li ser çi ye?', 'Di berhemê de evîna Mem û Zînê ya ku ji nû ve nayên cem hev vedibêje.', 'Di berhemê de evîna Mem û Zînê ya ku ji nû ve nayên cem hev vedibêje.', 'Eser, Mem ile Zîn''in kavuşamayan aşkını anlatır.', 'A'),
('044b1b40-db00-4fd1-a59c-c0afe1afd350', 'Bajarê Mêrdînê bi kîjan mîmariyê navdar e?', 'Mêrdîn bi mîmariya xwe ya kevirê zer navdar e.', 'Mêrdîn bi mîmariya xwe ya kevirê zer navdar e.', 'Mardin, sarı kesme taş mimarisiyle ünlüdür.', 'A'),
('04526f07-58b7-49bb-841b-593bffc2cbd0', 'Peyva "ciwan" bi Tirkî tê wateya "kadın".', 'Peyva "ciwan" tê wateya "genç".', 'Peyva "ciwan" tê wateya "genç".', '"ciwan" kelimesi "genç" demektir.', 'B'),
('04c6c52f-0d82-4d2c-9a0c-7adb84ad3626', 'Di çanda Kurdî de cil û bergên herêmî herî zêde bi kîjan qadê re têkildar e?', 'Cilên herêmî di çarçoveya kevneşopiya çanda kurdî de têne nirxandin.', 'Cilên herêmî di çarçoveya kevneşopiya çanda kurdî de têne nirxandin.', 'yerel kıyafetler, Kürt kültüründe gelenek bağlamında değerlendirilir.', 'C'),
('05088ba8-eaf5-4a07-a1e0-52ca91b048e0', 'Di Kurmancî de peyva "şev" bi Tirkî çi ye?', 'Peyva "şev" tê wateya "gece".', 'Peyva "şev" tê wateya "gece".', '"şev" kelimesi "gece" anlamına gelir.', 'B'),
('05099242-25b9-4163-ac8e-9eae610ec6c8', 'Wateya paşnavê "Cigerxwîn" çi ye?', '"Cigerxwîn" tê maneya kezeba şewitî/arîşe; Hesasiyeta helbestvan a li hember êş û azarên gel nîşan dide.', '"Cigerxwîn" tê maneya kezeba şewitî/arîşe; Hesasiyeta helbestvan a li hember êş û azarên gel nîşan dide.', '"Cigerxwîn" ciğeri yanık/dertli anlamına gelir; şairin halkın acılarına duyarlılığını yansıtır.', 'C'),
('0509f5b5-5103-48f5-889f-3fd301fc59b3', 'Yilmaz Guney navekî navdar ê bi eslê xwe kurd e di kîjan şaxê hunerê de ye?', 'Yılmaz Guney navekî bi eslê xwe kurd e ku di warê sînemayê de derdikeve pêş û bi fîlmên xwe yên wek "Yol" tê naskirin.', 'Yılmaz Guney navekî bi eslê xwe kurd e ku di warê sînemayê de derdikeve pêş û bi fîlmên xwe yên wek "Yol" tê naskirin.', 'Yılmaz Güney, "Yol" gibi filmleriyle tanınan, sinema alanında öne çıkmış Kürt kökenli bir isimdir.', 'B'),
('0535b4a7-b63b-4273-b7a1-4553e8ccd0c3', 'Peyva "sar" bi Tirkî tê wateya "soğuk".', 'Wekheviya rast ji bo "sar" "soğuk" e.', 'Wekheviya rast ji bo "sar" "soğuk" e.', '"sar" için doğru karşılık "soğuk"tir.', 'A'),
('05597cd5-b22f-4741-89c7-dcefcc7ec555', 'Di Kurmancî de peyva "hatin" bi Tirkî çi ye?', 'Peyva "hatin" tê wateya "gelmek".', 'Peyva "hatin" tê wateya "gelmek".', '"hatin" kelimesi "gelmek" anlamına gelir.', 'D'),
('056cd584-3483-4f7c-aaa9-72eb2bfe41e7', 'Di muzîka Kurdî de solo bi çi re têkildar e?', 'Solo di warê muzîka kurdî de bi performansa yek kesî ve girêdayî ye.', 'Solo di warê muzîka kurdî de bi performansa yek kesî ve girêdayî ye.', 'solo, Kürt müziği alanında tek kişinin icrası ile ilişkilidir.', 'A'),
('058cf604-6ffb-4ed7-a924-351204045050', 'Peyva "nav" bi Tirkî tê wateya "ad/isim".', 'Wekheviya rast ji bo "nav" "ad/isim" e.', 'Wekheviya rast ji bo "nav" "ad/isim" e.', '"nav" için doğru karşılık "ad/isim"tir.', 'A'),
('05cb9106-38f0-4f83-81f4-16ee7b2e7d23', 'Peyva "xwendegeh" bi Tirkî tê wateya "okul/akademi".', 'Wekheviya rast ji bo "xwendegeh" "okul/akademi" e.', 'Wekheviya rast ji bo "xwendegeh" "okul/akademi" e.', '"xwendegeh" için doğru karşılık "okul/akademi"tir.', 'A'),
('05cfeb04-09fa-4987-b4b7-59c774765f4a', '"Kerkük" li kîjan welatî ye?', 'Kerkûk bajarekî Iraqê ye ku bi statuya xwe ya dîrokî ya pirçandî û nakokbar tê naskirin.', 'Kerkûk bajarekî Iraqê ye ku bi statuya xwe ya dîrokî ya pirçandî û nakokbar tê naskirin.', 'Kerkük, Irak''ta, tarihsel olarak çok kültürlü ve tartışmalı statüsüyle bilinen bir şehirdir.', 'A'),
('0635f687-d29b-40d4-aab9-e448f418c696', 'Kevneşopiya Dengbêjiyê di bingeh de li ser çi ye?', 'Dengbêjlik kevneşopiyeke vegotinê ye ku bi devkî/bi dilê nifş bi nifş tê veguhestin.', 'Dengbêjlik kevneşopiyeke vegotinê ye ku bi devkî/bi dilê nifş bi nifş tê veguhestin.', 'Dengbêjlik, kuşaktan kuşağa sözlü/ezbere aktarılan bir anlatı geleneğidir.', 'D'),
('066045ef-b32a-4fa4-b437-271263675981', 'Çima xalîçe û tekstîlên kurdî di xebatên çandî de girîng in?', 'Tevn û motîfan der barê bîra herêmî, hilberîn û cîhana estetîk a civakan de îşaretan digirin.', 'Tevn û motîfan der barê bîra herêmî, hilberîn û cîhana estetîk a civakan de îşaretan digirin.', 'Dokuma ve motifler, toplulukların yerel hafıza, üretim ve estetik dünyasına dair ipuçları taşır.', 'A'),
('066c1057-f3ea-4926-94e2-91a7fd3231d1', 'Têgîna modernîteya demokratîk bi kîjan fikrê tê berovajîkirin?', 'Bi rexnekirina modernîteya demokratîk, modernîteya kapîtalîst, navendîparêzî û netew-dewleta monîst tê formulekirin.', 'Bi rexnekirina modernîteya demokratîk, modernîteya kapîtalîst, navendîparêzî û netew-dewleta monîst tê formulekirin.', 'Demokratik modernite, kapitalist modernite, merkeziyetçilik ve tekçi ulus-devlet eleştirisiyle formüle edilir.', 'A'),
('068896ad-b140-478d-a8ef-eb58c9338adc', 'Di Kurmancî de wateya "xwarin" çi ye?', '"Xwarin" bi Tirkî tê wateya "yemek (yeme eylemi)".', '"Xwarin" bi Tirkî tê wateya "yemek (yeme eylemi)".', null, 'D'),
('06c9bba7-73e0-4553-9d00-6d762dc2a0b2', '"Teyran" di paşnavê "Feqiyê Teyran" de bi çi re têkildar e?', '"Teyran" bi çûkan (teyr = çûk) ve girêdayî ye; Ew eleqeya helbestvan bi xweza û motîfên çûkan re nîşan dide.', '"Teyran" bi çûkan (teyr = çûk) ve girêdayî ye; Ew eleqeya helbestvan bi xweza û motîfên çûkan re nîşan dide.', '"Teyran" kuşlarla ilişkilidir (teyr = kuş); şairin doğa ve kuş motiflerine ilgisini yansıtır.', 'C'),
('06e2500e-e8c2-4943-b9ff-bfbef044bcde', 'Peyva "roj" bi Tirkî tê wateya "ev".', 'Peyva "roj" tê wateya "gün/güneş".', 'Peyva "roj" tê wateya "gün/güneş".', '"roj" kelimesi "gün/güneş" demektir.', 'B'),
('070b4208-11c6-46bc-8037-93694ae48302', 'Roman têgeheke edebiyata Kurdî ye.', 'Roman têgehek e ku ji bo têgihîştina metnên edebî tê bikaranîn.', 'Roman têgehek e ku ji bo têgihîştina metnên edebî tê bikaranîn.', 'roman edebi metinleri anlamada kullanılan bir kavramdır.', 'A'),
('0729456a-a987-4d7c-9635-087f66e7ae47', 'Komkujiyên ku Êzidî di dîrokê de rastî wan hatine, bi zimanê xwe çi ne?', 'Êzidî bi zimanê xwe komkujiyên ku hatine kirin "ferman" bi nav dikin.', 'Êzidî bi zimanê xwe komkujiyên ku hatine kirin "ferman" bi nav dikin.', 'Êzidîler, maruz kaldıkları katliamları kendi dillerinde "ferman" olarak adlandırır.', 'D'),
('07308d3d-166c-4e73-b41d-45264427defc', 'Herêma "Dersim" bi piranî bi kîjan kevneşopî re têkildar e?', 'Herêma Dêrsimê (Tuncelî) bi giranî bi kevneşopiya baweriya Elewî-Kizilbaş ve girêdayî ye.', 'Herêma Dêrsimê (Tuncelî) bi giranî bi kevneşopiya baweriya Elewî-Kizilbaş ve girêdayî ye.', 'Dersim (Tunceli) bölgesi, ağırlıkla Alevi-Kızılbaş inanç geleneğiyle anılır.', 'B'),
('07574570-9cee-4a0a-852e-d8cee6a281f2', 'Di konfederalîzma demokratîk de giraniya li ser “devletsiz demokrasi” tê çi wateyê?', 'Ev giranî fikra ku civak karibe bi rêya meclîsên xwecihî, komun û torên konfederal xwe bi rê ve bibe îfade dike.', 'Ev giranî fikra ku civak karibe bi rêya meclîsên xwecihî, komun û torên konfederal xwe bi rê ve bibe îfade dike.', 'Bu vurgu, yerel meclisler, komünler ve konfederal ağlarla toplumun kendi kendini yönetebilmesi fikrini anlatır.', 'A'),
('07777350-a56a-477f-aaee-351d6da9187f', 'Di çanda Kurdî de Newroz herî zêde bi kîjan qadê re têkildar e?', 'Newroz di çanda Kurdan de di çarçoveya 21 Adar de tê nirxandin.', 'Newroz di çanda Kurdan de di çarçoveya 21 Adar de tê nirxandin.', 'Newroz, Kürt kültüründe 21 Adar bağlamında değerlendirilir.', 'B'),
('077b93af-a29b-47b5-be1a-c8a3b6ca0b77', 'Navê ku yek ji yekem mewlûdên nivîskî yên zazakî (kirmanckî) daye kî ye?', 'Mela Ehmedê Xasî, Zazakî''de (Kirmanckî) ilk yazılı mevlitlerden birini vermesiyle bilinir.', null, null, 'B'),
('0799cfb5-d05b-45bb-a8be-67c7ffa594d0', 'Kîjan herêm bi tevgera "Şeyh Ubeydullah" (1880) ve girêdayî ye?', 'Tevgera Şêx Ubeydullah (1880) tevgereke kurd e ku li derdora Colemêrg-Şemdînanê derketiye holê.', 'Tevgera Şêx Ubeydullah (1880) tevgereke kurd e ku li derdora Colemêrg-Şemdînanê derketiye holê.', 'Şeyh Ubeydullah hareketi (1880), Hakkari-Şemdinan çevresinde ortaya çıkan bir Kürt hareketidir.', 'B'),
('07c6ff2c-eb29-4240-8e38-78118e965788', 'Ji rojên hefteyê "Duşem" kîjan roj e?', '"Duşem" yekem roja karsaziyê ya hefteyê, Duşem e.', '"Duşem" yekem roja karsaziyê ya hefteyê, Duşem e.', '"Duşem" haftanın ilk iş günü olan pazartesidir.', 'D'),
('07ef7659-cbf2-4e28-99c4-af61d3ab8c3f', 'Dengbêjî herî zêde li kîjan herêmê bi hêz e?', 'Kevneşopiya Dengbêjiyê bi taybetî li herêma Serhatê xurt e.', 'Kevneşopiya Dengbêjiyê bi taybetî li herêma Serhatê xurt e.', 'Dengbêjlik geleneği özellikle Serhat bölgesinde güçlüdür.', 'A'),
('07eff14a-b33b-4d37-8cf9-e3ac62914464', 'Peyva "rûniştin" bi Tirkî tê wateya "kalkmak".', 'Peyva "rûniştin" tê wateya "oturmak".', 'Peyva "rûniştin" tê wateya "oturmak".', '"rûniştin" kelimesi "oturmak" demektir.', 'B'),
('07f3abfe-b267-4137-9596-7f17362e8d84', 'Ji bilî kurdan kîjan gelên din Newrozê pîroz dikin?', 'Cejna Newrozê ji aliyê Kurd, Îranî û gelek gelên herêmê ve tê pîrozkirin.', 'Cejna Newrozê ji aliyê Kurd, Îranî û gelek gelên herêmê ve tê pîrozkirin.', 'Newroz/Nevruz, Kürtlerin yanı sıra İranlılar ve bölgedeki birçok halk tarafından kutlanır.', 'A'),
('084132e0-3540-4dbc-a499-c7f412054715', 'Di civaka Kurd de pêkhateyên eşîrî di dîrokê de xwedî kîjan fonksiyon in?', 'Avahiyên eşîrî di dîrokê de parçeyek ji torên hevgirtina civakî û desthilatdariya siyasî ne.', 'Avahiyên eşîrî di dîrokê de parçeyek ji torên hevgirtina civakî û desthilatdariya siyasî ne.', 'Aşiret yapıları tarihsel olarak sosyal dayanışma ve siyasal otorite ağlarının bir parçası olmuştur.', 'A'),
('085b0c78-c05a-49ab-acad-83c0ea8041ff', 'Gola Urmiyê (Urmiye) li kîjan welatî ye?', 'Gola Urmiyê goleke mezin e li bakurê rojavayê Îranê û nêzîkî herêma kurdan e.', 'Gola Urmiyê goleke mezin e li bakurê rojavayê Îranê û nêzîkî herêma kurdan e.', 'Urmiye Gölü, İran''ın kuzeybatısında, Kürt bölgesine yakın büyük bir göldür.', 'A'),
('085cc397-0ea2-4399-a78c-5613fc090759', 'Peyva "îro" bi Tirkî tê wateya "bugün".', 'Wekheviya rast ji bo "îro" "bugün" e.', 'Wekheviya rast ji bo "îro" "bugün" e.', '"îro" için doğru karşılık "bugün"tir.', 'A'),
('085d5b8b-adff-424f-9533-d6ec1f68c6a7', 'Di konfederalîzma demokratîk de biryargirtin çawa dixebite?', 'Di konfederalîzma demokratîk de, ji komîn û meclîsên bingehîn dest pê dike, biryar bi awayekî beşdariyê tên girtin.', 'Di konfederalîzma demokratîk de, ji komîn û meclîsên bingehîn dest pê dike, biryar bi awayekî beşdariyê tên girtin.', 'Demokratik konfederalizmde kararlar, tabandaki komün ve meclislerden başlayarak katılımcı biçimde alınır.', 'D'),
('088f0730-2165-44ea-8b6f-d4000da137b8', 'Kesê ku govendê dikişîne (başını çeker) re çi tê gotin?', 'Ji kesê ku îdare û serê xaltiyê dike sergovend tê gotin.', 'Ji kesê ku îdare û serê xaltiyê dike sergovend tê gotin.', 'Halayı yöneten ve başını çeken kişiye sergovend denir.', 'A'),
('08f04160-6cf1-4d98-bf8d-c23772b4276b', 'Peyva "çem" bi Tirkî tê wateya "nehir".', 'Wekheviya rast ji bo "çem" "nehir" e.', 'Wekheviya rast ji bo "çem" "nehir" e.', '"çem" için doğru karşılık "nehir"tir.', 'A'),
('08fe6b70-4dff-45c2-9b96-2c19720e2098', 'Piştî Şerê Cîhanê yê Yekem behsa kîjan peymanê jî tê kirin?', 'Di Peymana Sewrê ya sala 1920an de xalên derbarê otonomî/statûya kurdan de hebûn.', 'Di Peymana Sewrê ya sala 1920an de xalên derbarê otonomî/statûya kurdan de hebûn.', '1920 Sevr Antlaşması, Kürtlerin özerkliğine/statüsüne dair maddeler içeriyordu.', 'C'),
('0914a849-60a2-4627-b9fb-9f73b739bc05', 'Selahedînê Eyûbî li kîjan bajarî ji dayik bûye?', 'Selahedîn Eyûbî li bajarê Tikrîtê ku li Iraqa îro ye ji dayîk bûye.', 'Selahedîn Eyûbî li bajarê Tikrîtê ku li Iraqa îro ye ji dayîk bûye.', 'Selahaddin Eyyubi, bugünkü Irak''ta yer alan Tikrit''te doğmuştur.', 'C'),
('0958f003-43f9-4e56-ad94-b7ce2ed408eb', 'Cigerxwîn berhemên xwe bi kîjan zimanî nivîsandine?', 'Cigerxwîn, şiirlerini Kürtçe (Kurmancî) yazmıştır.', null, null, 'A'),
('09691a2e-71a5-4efd-bfca-f6e66d0eb861', 'Peyva "pisîk" bi Tirkî tê wateya "nehir".', 'Peyva "pisîk" tê wateya "kedi".', 'Peyva "pisîk" tê wateya "kedi".', '"pisîk" kelimesi "kedi" demektir.', 'B'),
('096d3c6a-4674-4625-8a51-972cfae5c395', 'Sê axên sereke yên konfederalîzma demokratîk çi ne?', 'Xalên sereke yên paradîgmayê azadiya jinê, civaka ekolojîk û demokrasiya bingehîn e.', 'Xalên sereke yên paradîgmayê azadiya jinê, civaka ekolojîk û demokrasiya bingehîn e.', 'Paradigmanın temel eksenleri kadın özgürlüğü, ekolojik toplum ve taban demokrasisidir.', 'A'),
('098e9425-b919-4712-8401-b06c8bb0d237', 'Afirînerê efsanewî yê bi motîfa marê ku di çanda herêmê de hevpar e kîjan e?', 'Şahmaran mexlûqekî efsanewî ye ku li herêmê belav bûye, nîv mirov û nîv mar tê nîşandan.', 'Şahmaran mexlûqekî efsanewî ye ku li herêmê belav bûye, nîv mirov û nîv mar tê nîşandan.', 'Şahmaran, yarı insan yarı yılan biçiminde tasvir edilen, bölgede yaygın efsanevi bir varlıktır.', 'A'),
('098ebe0e-1229-49f5-a76a-02004f17b927', 'Tevgera jinên Kurd herî zêde bi kîjan prensîbê derdikeve pêş?', 'Tevgera jinên Kurd bi rêgeza azadiya jinê û bi rêxistinbûna jinan a xweser (xweser) derdikeve pêş.', 'Tevgera jinên Kurd bi rêgeza azadiya jinê û bi rêxistinbûna jinan a xweser (xweser) derdikeve pêş.', 'Kürt kadın hareketi, kadın özgürlüğü ve kadınların özerk (kendi) örgütlenmesi ilkesiyle öne çıkar.', 'D'),
('0996a060-4f60-4df8-bb02-386dabc7dec3', 'Wateya peyva "Dîrok" çi ye?', '"Dîrok" tê wateya tarîx; Navê kategoriyê di serîlêdanê de ji vir tê.', '"Dîrok" tê wateya tarîx; Navê kategoriyê di serîlêdanê de ji vir tê.', '"Dîrok" tarih demektir; uygulamadaki kategori adı da buradan gelir.', 'B'),
('0a6d85fa-b27f-439b-ac9f-98da17c3ee02', 'Newroz bi kîjan efsaneyê ve girêdayî ye?', 'Newroz bi efsaneya serhildana hesinkar Kawayê li dijî Dehakê zalim ve girêdayî ye.', 'Newroz bi efsaneya serhildana hesinkar Kawayê li dijî Dehakê zalim ve girêdayî ye.', 'Newroz, demirci Kawa''nın zalim Dehak''a başkaldırısını anlatan efsaneyle ilişkilendirilir.', 'D'),
('0a733f30-88fa-4bd6-9ed0-9ba845667f29', 'Selahedîn bi vegerandina kîjan bajarî ji xaçperestan navdar e?', 'Selahedîn bi vegerandina Qudsê ji Xaçperestan di sala 1187an de tê zanîn.', 'Selahedîn bi vegerandina Qudsê ji Xaçperestan di sala 1187an de tê zanîn.', 'Selahaddin Eyyubi, 1187''de Kudüs''ü Haçlılardan geri almasıyla tanınır.', 'C'),
('0a7fa162-dc97-45dc-bf51-ea29ee31891a', 'Kîjan nivîskar/helbestvan herî zêde bi berhema kurdî ya klasîk Mem û Zîn ve girêdayî ye?', 'Mem û Zîn di edebiyata kurdî de yek ji berhemên herî girîng ên Ehmedê Xanî tê dîtin.', 'Mem û Zîn di edebiyata kurdî de yek ji berhemên herî girîng ên Ehmedê Xanî tê dîtin.', 'Mem û Zîn, Ehmedê Xanî’nin Kürt edebiyatındaki en önemli eserlerinden biri kabul edilir.', 'A'),
('0aa1f82a-5483-499e-9b36-30133cc31700', 'Peyva "dê" bi Tirkî tê wateya "anne".', 'Wekheviya rast ji bo "dê" "anne" e.', 'Wekheviya rast ji bo "dê" "anne" e.', '"dê" için doğru karşılık "anne"tir.', 'A'),
('0aa9bf50-a921-426b-86b8-e19d363ce704', 'Laleş cihê pîroz ê Êzidiyan li kîjan welatî ye?', 'Laleş perestgeha li bakurê Iraqê ye û ji bo êzdiyan perestgeha herî pîroz tê dîtin.', 'Laleş perestgeha li bakurê Iraqê ye û ji bo êzdiyan perestgeha herî pîroz tê dîtin.', 'Laleş, Irak''ın kuzeyinde yer alan ve Êzidîler için en kutsal sayılan tapınaktır.', 'C'),
('0b000a5a-3c5e-49cf-85aa-1b5e93099ed5', '"Anadil"-a rast di paradîgmayê de herî zêde bi çi ve girêdayî ye?', 'Mafê zimanê zikmakî bi parastina hebûn û nasnameya çandî ve girêdayî ye.', 'Mafê zimanê zikmakî bi parastina hebûn û nasnameya çandî ve girêdayî ye.', 'Anadil hakkı, kültürel varoluş ve kimliğin sürdürülmesiyle ilişkilendirilir.', 'C'),
('0b6405d6-facc-4433-b405-4e73f8db1dd0', 'Diyasporaya Kurdî herî zêde kîjan hewcedariyê ji bo zindî bihêle?', 'Sazî û weşanên dîasporayê ji bo veguhestina ziman û bîra çandî di navbera nifşan de girîng in.', 'Sazî û weşanên dîasporayê ji bo veguhestina ziman û bîra çandî di navbera nifşan de girîng in.', 'Diaspora kurumları ve yayınları, dilin ve kültürel belleğin kuşaklar arasında aktarılması için önemlidir.', 'A'),
('0b80d22b-95fd-466a-9750-ad8c648b5d04', 'Peyva "Başûr" ji aliyê erdnîgarî ve bi kurdî tê çi wateyê?', '"Başûr" tê wateya başûr; Bi giranî ji bo Herêma Kurdistanê li Iraqê tê bikaranîn.', '"Başûr" tê wateya başûr; Bi giranî ji bo Herêma Kurdistanê li Iraqê tê bikaranîn.', '"Başûr" güney demektir; ağırlıkla Irak''taki Kürt bölgesi için kullanılır.', 'A'),
