with patch(id,prompt,explanation,explanation_ku,explanation_tr,correct_option) as (values
('2e6b6423-46e6-48a0-a282-9294124bfd59', 'Bajarê "Afrîn" li kîjan welatî ye?', 'Efrîn wargeheke kurdan e li bakurê rojavayê Sûriyê.', 'Efrîn wargeheke kurdan e li bakurê rojavayê Sûriyê.', 'Afrîn, Suriye''nin kuzeybatısında bir Kürt yerleşimidir.', 'D'),
('2eae7972-9216-4907-95f7-eec464017c06', 'Urartû navenda xwe li kîjan derê bû?', 'Paytextê Mîrektiya Ûrartûyan Tûşpa li qeraxa Gola Wanê bû.', 'Paytextê Mîrektiya Ûrartûyan Tûşpa li qeraxa Gola Wanê bû.', 'Urartu Krallığı''nın başkenti Van Gölü kıyısındaki Tuşpa''ydı.', 'B'),
('2ec280f7-44bd-48d2-bd33-e6729e8d8316', 'Çima Peymana Sevrê ya 1920’an di warê pirsgirêka Kurd de gelek caran tê gotin?', 'Sevrê di nîqaşên siyasî yên nûjen ên kurdan de ji bo nîqaşên otonomî û statuya muhtemel tê binavkirin.', 'Sevrê di nîqaşên siyasî yên nûjen ên kurdan de ji bo nîqaşên otonomî û statuya muhtemel tê binavkirin.', 'Sevr, modern Kürt siyasi tartışmalarında özerklik ve olası statü tartışmaları nedeniyle referans verilir.', 'A'),
('2edc356f-4536-45e7-a7e2-483d08c97534', '"Mahabad Cumhuriyeti" bi çi awayî girîngiya sembolîk heye?', 'Komara Mehabadê (1946) wek yek ji yekem serpêhatiyên dewleta kurdî ya nûjen xwedî girîngiyeke sembolîk e.', 'Komara Mehabadê (1946) wek yek ji yekem serpêhatiyên dewleta kurdî ya nûjen xwedî girîngiyeke sembolîk e.', 'Mahabad Cumhuriyeti (1946), ilk modern Kürt devlet deneyimlerinden biri olarak simgesel önem taşır.', 'C'),
('2ef4e99f-1673-4199-b4d1-103e1ef5853d', 'Kurd bi giştî weke kîjan civakê tên pênasekirin?', 'Britannica Kurdan weke civakeke etnîkî û zimanî pênase dike.', 'Britannica Kurdan weke civakeke etnîkî û zimanî pênase dike.', 'Britannica, Kürtleri etnik ve dilsel bir topluluk olarak tanımlar.', 'A'),
('2f16bae0-accb-417e-8f6d-c7bb23511afa', 'Peyva "baran" bi Tirkî tê wateya "kar".', 'Peyva "baran" tê wateya "yağmur".', 'Peyva "baran" tê wateya "yağmur".', '"baran" kelimesi "yağmur" demektir.', 'B'),
('2f70911a-53d9-4976-a7cb-f17416422016', 'daristan yek ji têgehên ji bo têgihîştina erdnîgariya Kurdistanê ye.', 'Erdnîgarî jîngeha xwezayî û mirovan lêkolîn dike.', 'Erdnîgarî jîngeha xwezayî û mirovan lêkolîn dike.', 'Coğrafya doğal ve beşeri çevreyi inceler.', 'A'),
('2fb5be27-eba0-4ec5-a1dd-07acf28c21fb', 'Di derbarê govend de kîjan rasttir e?', 'govend di çanda kurdî de bi cihê dawet û şahiyan ve girêdayî ye.', 'govend di çanda kurdî de bi cihê dawet û şahiyan ve girêdayî ye.', 'govend, Kürt kültüründe düğün ve kutlama alanıyla bağlantılıdır.', 'A'),
('302fe4f4-a5b8-4735-b63c-a775695c4f96', 'Helbestvanê mezin ê bi nasnav "Cizîrî" bi kîjan bajarî tê bîranîn?', 'Melayê Cizîrî, adını yaşadığı Cizre (Cizîr) şehrinden alır.', null, null, 'D'),
('3040ace5-2216-4cea-b8c2-b1cb7d61501d', 'Geliyê Mûnzûrê bi piranî li derdora kîjan parêzgehê ye?', 'Geliyê Mûnzûrê û Çiyayên Mûnzûrê li derdora Tunceliyê (Dêrsim) in.', 'Geliyê Mûnzûrê û Çiyayên Mûnzûrê li derdora Tunceliyê (Dêrsim) in.', 'Munzur Vadisi ve Munzur Dağları, Tunceli (Dersim) çevresinde yer alır.', 'A'),
('3055832c-c2e1-44af-8132-c8638266ddbb', 'Çima qada ravekirinê di pirsekê de girîng e?', 'Ravekirin bi kurtî û agahdarî nîşan dide ku çima bersiv rast e.', 'Ravekirin bi kurtî û agahdarî nîşan dide ku çima bersiv rast e.', 'Açıklama, cevabın neden doğru olduğunu kısa ve öğretici şekilde gösterir.', 'B'),
('30666c85-eeb6-42eb-b7cb-8b1e8d1b1293', 'Tembûr û tembûr di çanda kurdî de bi kîjan qadê ve girêdayî ye?', 'Def û tembûr enstrumanên girîng in ku di kevneşopiya muzîka kurdî û herêmî de rîtm û awaz hildigirin.', 'Def û tembûr enstrumanên girîng in ku di kevneşopiya muzîka kurdî û herêmî de rîtm û awaz hildigirin.', 'Def ve tembûr, Kürt ve bölge müzik geleneklerinde ritim ve ezgi taşıyan önemli çalgılardır.', 'D'),
('307238ca-3edd-4179-9778-5cec0a7ec746', 'Peyva "newal" bi Tirkî tê wateya "ova".', 'Peyva "newal" tê wateya "vadi".', 'Peyva "newal" tê wateya "vadi".', '"newal" kelimesi "vadi" demektir.', 'B'),
('30da9f23-caba-432c-82ac-dcd13778dbd4', 'Paşgira "-istan" çi çêdike?', '"-istan" navê cih/welat distîne: wek gulistan (baxçê gulan).', '"-istan" navê cih/welat distîne: wek gulistan (baxçê gulan).', '"-istan" yer/ülke adı türetir: gulistan (gül bahçesi) gibi.', 'D'),
('30e8db37-a7c5-4a92-bf55-50ab9f7de520', 'Peyva "xwendekar" bi Tirkî tê wateya "grup".', '"xwendekar" tê wateya "öğrenci"; "kom" tê wateya "grup".', '"xwendekar" tê wateya "öğrenci"; "kom" tê wateya "grup".', '"xwendekar" "öğrenci" demektir; "kom" ise "grup" anlamına gelir.', 'B'),
('30f73ee8-1325-4b31-a2b8-8f206d2761da', 'Peyva "newal" bi Tirkî tê wateya "vadi".', 'Wekheviya rast ji bo "newal" "vadi" e.', 'Wekheviya rast ji bo "newal" "vadi" e.', '"newal" için doğru karşılık "vadi"tir.', 'A'),
('3137a278-a0a0-4e22-a7b8-292d67938830', 'Di kevneşopiya klasîk de bi gelemperî ji çîrokên lehengiyê re çi tê gotin?', 'Ji berhemên beyt/devkî yên ku lehengî û bûyerên mezin vedibêjin, destan tê gotin.', 'Ji berhemên beyt/devkî yên ku lehengî û bûyerên mezin vedibêjin, destan tê gotin.', 'Kahramanlık ve büyük olayları anlatan manzum/sözlü eserlere destan denir.', 'B'),
('3155304a-c196-4066-b399-a8269c12b44e', 'Di baweriya Êzdiyatiyê de kîjan kesayet pîroz tê dîtin?', 'Êzidî inancında Melek Tavus (Tawûsî Melek) merkezî ve kutsal bir figürdür.', null, null, 'C'),
('3191a3c9-34a4-4fe2-acf0-9f3380b193a3', 'Çiyayên Zagrosê bi giranî bi kîjan welatan ve dirêj dibin?', 'Çiyayên Zagrosê sîstemeke çiyayî ye ku bi Kurdan tê naskirin û bi giranî li seranserê Îran û Iraqê belav dibe.', 'Çiyayên Zagrosê sîstemeke çiyayî ye ku bi Kurdan tê naskirin û bi giranî li seranserê Îran û Iraqê belav dibe.', 'Zagros dağları, ağırlıkla İran ve Irak boyunca uzanan, Kürtlerle özdeşleşmiş bir dağ sistemidir.', 'B'),
('319dc093-a25d-4862-8f47-d2b62e6d74f9', 'Di Kurmancî de wateya "goşt" çi ye?', '"Goşt" bi Tirkî tê wateya "et".', '"Goşt" bi Tirkî tê wateya "et".', null, 'D'),
('31ab4130-aa70-4ddb-972c-f8481eb14b92', 'Amûra "bilûr" çi ye?', 'Bilûr lûleya bayê ye ku şivanan lêdixin.', 'Bilûr lûleya bayê ye ku şivanan lêdixin.', 'Bilûr, çobanların çaldığı üflemeli kavaldır.', 'D'),
('31b37951-5dbf-4a47-85e1-45d5513e5a03', 'Di Kurmancî de peyva "zanîn" bi Tirkî çi ye?', 'Peyva "zanîn" tê wateya "bilmek".', 'Peyva "zanîn" tê wateya "bilmek".', '"zanîn" kelimesi "bilmek" anlamına gelir.', 'B'),
('31f2487e-be93-49a3-913e-e141cab05a01', '"Wan" navê kurdî yê kîjan bajarî ye?', '"Wan" navê kurdî yê bajarê Wanê ye.', '"Wan" navê kurdî yê bajarê Wanê ye.', '"Wan", Van şehrinin Kürtçe adıdır.', 'A'),
('325db23c-1124-4d8d-85d5-cda7e10d48e0', 'Di Kurmancî de "bîst" kîjan hejmar e?', '"Bîst" bi Tirkî tê wateya "yirmi".', '"Bîst" bi Tirkî tê wateya "yirmi".', null, 'A'),
('326672a0-95ff-42bb-a03f-f6c2de176a5a', 'Wateya "Navê te çi ye?" bi Tirkî çi ye?', '"Navê te çi ye?" bi Tirkî tê wateya "adın ne?".', '"Navê te çi ye?" bi Tirkî tê wateya "adın ne?".', null, 'A'),
('328d1991-110b-4bd1-a323-eea3f390ca99', 'Kî yekem peyva "Jineolojî" pêşniyar kir?', 'Têgîna jineolojiyê yekem car ji aliyê Abdullah Ocalan ve hate pêşniyarkirin û ji aliyê tevgera jinê ve hate pêşxistin.', 'Têgîna jineolojiyê yekem car ji aliyê Abdullah Ocalan ve hate pêşniyarkirin û ji aliyê tevgera jinê ve hate pêşxistin.', 'Jineolojî terimi, ilk olarak Abdullah Öcalan tarafından önerilmiş ve kadın hareketince geliştirilmiştir.', 'B'),
('32beea99-8d75-48a2-8b55-6b5051e655ba', 'Têgînên "Mela" û "feqî" bi kîjan saziyê ve girêdayî ne?', '"Mela" (alim) û "feqî" (xwendekar) têgehên bi kevneşopiya medreseyê ve girêdayî ne.', '"Mela" (alim) û "feqî" (xwendekar) têgehên bi kevneşopiya medreseyê ve girêdayî ne.', '"Mela" (âlim) ve "feqî" (talebe), medrese geleneğiyle ilişkili kavramlardır.', 'A'),
('32cc55cb-5e89-4c56-b6d6-c949dfc599a4', '"Jineolojî" herî zêde kîjan agahdariyê rexne dike?', 'Jineolojî feraseta zanîn û zanistê ya serdest a mêr (patriarkal) rexne dike û nêzîkatiya jin-navendê pêşniyar dike.', 'Jineolojî feraseta zanîn û zanistê ya serdest a mêr (patriarkal) rexne dike û nêzîkatiya jin-navendê pêşniyar dike.', 'Jineolojî, erkek-egemen (patriyarkal) bilgi ve bilim anlayışını eleştirerek kadın eksenli bir yaklaşım önerir.', 'C'),
('32fc8723-5e82-4f21-8e45-c1d4a3cf84cd', 'Di Kurmancî de wateya "xwendin" çi ye?', '"Xwendin" bi Tirkî tê wateya "okumak (ve öğrenmek)".', '"Xwendin" bi Tirkî tê wateya "okumak (ve öğrenmek)".', null, 'A'),
('334961ca-e81c-4aad-9c56-fdcdab3cb7b3', 'Di Kurmancî de peyva "reng" bi Tirkî çi ye?', 'Peyva "reng" tê wateya "renk".', 'Peyva "reng" tê wateya "renk".', '"reng" kelimesi "renk" anlamına gelir.', 'B'),
('337f1b07-73a0-4a4d-a38c-7cfa4d3b876c', '"Şerefname" di kîjan sedsalê de hatiye nivîsandin?', 'Şerefnameya Şeref Han di sala 1597 an de di dawiya sedsala 16an de hatiye nivîsandin.', 'Şerefnameya Şeref Han di sala 1597 an de di dawiya sedsala 16an de hatiye nivîsandin.', 'Şeref Han''ın Şerefname''si 1597''de, yani 16. yüzyıl sonunda yazılmıştır.', 'D'),
('338861f9-897f-48e9-93be-158e6cc7b0f3', 'Di Kurmancî de wateya "sal" çi ye?', '"Sal" bi Tirkî tê wateya "yıl".', '"Sal" bi Tirkî tê wateya "yıl".', null, 'D'),
('339a01b1-f5cb-4284-978b-a65b3d4fbdff', 'Peyva "welat" bi Tirkî tê wateya "ülke/vatan".', 'Wekheviya rast ji bo "welat" "ülke/vatan" e.', 'Wekheviya rast ji bo "welat" "ülke/vatan" e.', '"welat" için doğru karşılık "ülke/vatan"tir.', 'A'),
('33f7392d-b4da-4ce2-9bc9-50b7c9ad6da4', 'Sûrên Diyarbekirê û Baxçeyên Hevselê bi kîjan çemî tên naskirin?', 'Di pênaseya UNESCO’yê de ev dever dîmeneke çandî ya li ser çemê Dîcleya Jorîn e.', 'Di pênaseya UNESCO’yê de ev dever dîmeneke çandî ya li ser çemê Dîcleya Jorîn e.', 'UNESCO tanımında alan, Yukarı Dicle Nehri Havzası üzerindeki bir kültürel peyzajdır.', 'B'),
('342598b5-9d11-409d-9bd5-06315220d21d', '“dil canlandırması” di edebiyata kurdî de tê çi wateyê?', 'Vejandina ziman hewldanek e ji bo xurtkirina bikaranîna giştî, edebî û dîjîtal a zimanên ku ji bindestî û kêmasiyên çavkaniyan hatine.', 'Vejandina ziman hewldanek e ji bo xurtkirina bikaranîna giştî, edebî û dîjîtal a zimanên ku ji bindestî û kêmasiyên çavkaniyan hatine.', 'Dil canlandırması, baskı ve kaynak eksikliği yaşamış dillerin kamusal, edebi ve dijital kullanım alanlarını güçlendirme çabasıdır.', 'B'),
('349a71af-0288-4607-8f62-4d8f1a5d5a3c', '"Qazi Muhammed" sembola têkoşîna xwerêvebirinê ya kîjan gelan e?', 'Qazî Mihemed yek ji sembolên Komara Mehabadê û têkoşîna Kurdan a ji bo çarenivîsê ye.', 'Qazî Mihemed yek ji sembolên Komara Mehabadê û têkoşîna Kurdan a ji bo çarenivîsê ye.', 'Qazi Muhammed, Mahabad Cumhuriyeti ile Kürtlerin kendi kaderini tayin mücadelesinin simgelerindendir.', 'C'),
('349c2b75-b298-4271-adca-bd3e7cde986f', 'Di Kurmancî de peyva "rabûn" bi Tirkî çi ye?', 'Peyva "rabûn" tê wateya "kalkmak".', 'Peyva "rabûn" tê wateya "kalkmak".', '"rabûn" kelimesi "kalkmak" anlamına gelir.', 'C'),
('34cd58b2-01d3-4d80-ab65-a66621293cdd', 'Di cil û bergên jinên kurd ên kevneşopî de hêmanên sereke çi ne?', 'Di kincên kevneşopî yên jinan de kincên dirêj ên rengîn û qat (kras/fistan) derdikevin pêş.', 'Di kincên kevneşopî yên jinan de kincên dirêj ên rengîn û qat (kras/fistan) derdikevin pêş.', 'Geleneksel kadın kıyafetinde renkli, katmanlı uzun elbiseler (kras/fistan) öne çıkar.', 'A'),
('34d2e77d-42d0-4863-9247-f962490c41f0', 'Di Kurmancî de peyva "spas" bi Tirkî çi ye?', 'Peyva "spas" tê wateya "teşekkür".', 'Peyva "spas" tê wateya "teşekkür".', '"spas" kelimesi "teşekkür" anlamına gelir.', 'C'),
('35136e37-3a25-46ea-8940-03896a54195b', 'Di baweriya Elewî-Kurd de îbadet-merasîma kolektîf çi tê gotin?', '"Cem" di baweriya Elewiyan de îbadet û kombûna kolektîf e.', '"Cem" di baweriya Elewiyan de îbadet û kombûna kolektîf e.', '"Cem", Alevi inancında topluca yapılan ibadet ve toplanma törenidir.', 'B'),
