with patch(id,prompt,explanation,explanation_ku,explanation_tr,correct_option) as (values
('456b6a69-db02-448e-a722-720db4119cde', '"Eş başkanlık" yekem car ji hêla giraniyê ve li ku hate sepandin?', 'Hevserokatiyê bi giranî li ser pêkhateyên siyasî û şaredariyên Kurdan dest pê kir.', 'Hevserokatiyê bi giranî li ser pêkhateyên siyasî û şaredariyên Kurdan dest pê kir.', 'Eş başkanlık, ağırlıkla Kürt siyasi yapıları ve belediyelerde uygulanmaya başlamıştır.', 'A'),
('46142c7c-f00b-4da5-a04f-64d03aecec37', 'Wateya peyva “roj” di kurdî de bi wateya xwe ya herî bingehîn çi ye?', 'Roj di kurdî de bi qada semantîk “gün” û “güneş” ve girêdayî ye; Di navên cihan ên wekî Rojava de jî tê dîtin.', 'Roj di kurdî de bi qada semantîk “gün” û “güneş” ve girêdayî ye; Di navên cihan ên wekî Rojava de jî tê dîtin.', 'Roj, Kürtçede “gün” ve “güneş” anlam alanıyla ilişkilidir; Rojava gibi yer adlarında da görülür.', 'A'),
('4614326f-9205-4300-a7a0-55d2e1e063f4', '"Deşt" bi Tirkî çi ye?', '"deşt" bi Tirkî tê wateya "ova".', '"deşt" bi Tirkî tê wateya "ova".', null, 'A'),
('469a8d72-2073-4087-acd2-84d1cc393f68', '"Hewlêr" (Hewlêr) Kîjan avahî di lîsteya mîrata cîhanî ya UNESCO de ye?', 'Hewlêr bi kelha xwe ya dîrokî di lîsteya Mîrateya Cîhanî ya UNESCOyê de ye.', 'Hewlêr bi kelha xwe ya dîrokî di lîsteya Mîrateya Cîhanî ya UNESCOyê de ye.', 'Erbil, tarihî höyük-kalesiyle UNESCO Dünya Mirası listesindedir.', 'C'),
('46d3486c-1b5f-45d9-af9c-34ebf68c99a3', 'Peyva "axaftin" bi Tirkî tê wateya "konuşmak".', 'Wekheviya rast ji bo "axaftin" "konuşmak" e.', 'Wekheviya rast ji bo "axaftin" "konuşmak" e.', '"axaftin" için doğru karşılık "konuşmak"tir.', 'A'),
('46fa37b7-bd4c-4960-9133-b19dbc1d92c4', 'Di Kurmancî de peyva "deşt" bi Tirkî çi ye?', 'Peyva "deşt" tê wateya "ova".', 'Peyva "deşt" tê wateya "ova".', '"deşt" kelimesi "ova" anlamına gelir.', 'B'),
('4705f5eb-9657-41df-aabd-48efe88bcfda', 'Wateya "Govend" di çanda kurdî de çi ye?', 'Govend govendeke kolektîf e ku bi hesta yekîtî û hevgirtinê tê meşandin.', 'Govend govendeke kolektîf e ku bi hesta yekîtî û hevgirtinê tê meşandin.', 'Govend, birlik ve dayanışma duygusuyla el ele oynanan toplu bir danstır.', 'A'),
('470825f0-c649-4e26-b141-245fc16da3f9', 'Peyva "biçûk" bi Tirkî tê wateya "yeni".', '"biçûk" tê wateya "küçük"; "nû" tê wateya "yeni".', '"biçûk" tê wateya "küçük"; "nû" tê wateya "yeni".', '"biçûk" "küçük" demektir; "nû" ise "yeni" anlamına gelir.', 'B'),
('47571ee5-c82c-4f22-aad4-48d9b4e6a1fd', 'Di navdêrên herêmî yên kurdî de bêjeya Bakur ji bo kîjan herêmê tê bikaranîn?', 'Bakur tê maneya “kuzey” û navekî hevpar ê herêma kurdan li Tirkiyê ye.', 'Bakur tê maneya “kuzey” û navekî hevpar ê herêma kurdan li Tirkiyê ye.', 'Bakur “kuzey” anlamındadır ve Türkiye’deki Kürt coğrafyası için yaygın bir addır.', 'A'),
('476fd9df-190c-40a8-b3ec-d4fec64d8fde', '"Çewlîg" navê kurdî yê kîjan bajarî ye?', '"Çewlîg" navê kurdî yê bajarê Çewlikê ye.', '"Çewlîg" navê kurdî yê bajarê Çewlikê ye.', '"Çewlîg", Bingöl şehrinin Kürtçe adıdır.', 'A'),
('47b34468-2b0b-48cf-9a48-1991ea040758', 'Di muzîka Kurdî de ravekirina "nîşana nivîsandina muzîkê" kîjan têgehê diyar dike?', 'Têgeha rast ''not'' e.', 'Têgeha rast ''not'' e.', 'Doğru kavram ''nota''tir.', 'A'),
('47b51843-799c-476d-892f-0df05fbe937a', 'Ji bilî hevserokatiyê mekanîzmayeke din a azadiya jinê çi ye?', 'Kotaya jinê li gel hevserokatiyê mekanîzmayeke ku temsîliyeta jinê misoger dike.', 'Kotaya jinê li gel hevserokatiyê mekanîzmayeke ku temsîliyeta jinê misoger dike.', 'Kadın kotası, eş başkanlıkla birlikte kadın temsilini güvenceye alan bir mekanizmadır.', 'B'),
('47ba24ea-1619-44b3-9b39-7174b9add727', 'Di Kurmancî de wateya "sêv" çi ye?', '"Sêv" bi Tirkî tê wateya "elma".', '"Sêv" bi Tirkî tê wateya "elma".', null, 'C'),
('47be7cdf-9e28-4b8d-bdce-10c967baa0dd', 'Di Kurmancî de "sê" kîjan hejmar e?', '"Sê" bi Tirkî tê wateya "üç".', '"Sê" bi Tirkî tê wateya "üç".', null, 'D'),
('47c3078f-5b43-4604-a76e-e669b5d3d678', 'Di derbarê pêjgeha gelêrî de kîjan rasttir e?', 'Pêjgeha gelêrî di çanda kurdan de bi qada çanda sifreyê ve girêdayî ye.', 'Pêjgeha gelêrî di çanda kurdan de bi qada çanda sifreyê ve girêdayî ye.', 'halk mutfağı, Kürt kültüründe sofra kültürü alanıyla bağlantılıdır.', 'A'),
('47db29fe-b4bf-426c-aaa7-63f83f0fb79e', 'Mêrdîn (Mêrdîn) bi çi navdar e?', 'Mêrdîn bi xaniyên xwe yên kevirîn û dîmenên ku li deşta Mezopotamyayê dinerin navdar e.', 'Mêrdîn bi xaniyên xwe yên kevirîn û dîmenên ku li deşta Mezopotamyayê dinerin navdar e.', 'Mardin, taş evleri ve Mezopotamya ovasına bakan manzarasıyla ünlüdür.', 'A'),
('47f2b1c9-19a5-4000-ac1a-2d7ec6e4cad2', 'Tevgera Mehabad û Barzanî di kîjan sedsalê de derketiye pêş?', 'Komara Mehabadê û tevgera Barzanî bi giranî di sedsala 20. de derketiye pêş.', 'Komara Mehabadê û tevgera Barzanî bi giranî di sedsala 20. de derketiye pêş.', 'Mahabad Cumhuriyeti ve Barzanî hareketleri, ağırlıkla 20. yüzyılda öne çıkmıştır.', 'C'),
('486cdb2a-ff2a-4eaa-b6c1-ca87dd661830', 'Kîjan sembol girîngiya ku di Êzdayetiyê de ji ronahiyê/rojê re hatiye dayîn radixe ber çavan?', 'Melek Tavûs û motîfa ronahî/rojê di baweriya Êzdiyan de xwedî girîngiyeke bingehîn e.', 'Melek Tavûs û motîfa ronahî/rojê di baweriya Êzdiyan de xwedî girîngiyeke bingehîn e.', 'Êzidî inancında Melek Tavus ve ışık/güneş motifi merkezî bir öneme sahiptir.', 'B'),
('4884e237-b9bf-4efc-b5e1-e3bca191c66c', 'Di dîroknasiya kurdî de berhema bi navê Şerefname bi kê re tê girêdan?', 'Şerefname yek ji çavkaniyên girîng ên destpêkê yên li ser mîrnişîn û xanedanên Kurdan e.', 'Şerefname yek ji çavkaniyên girîng ên destpêkê yên li ser mîrnişîn û xanedanên Kurdan e.', 'Şerefname, Kürt emirlikleri ve hanedanları hakkında erken dönem önemli kaynaklardan biridir.', 'A'),
('488513a6-185f-4d44-a0a9-0a5575bff9ca', 'Xwarinên biamiya/bamyayê dikevin kîjan kategoriyê?', 'Okra di xwarinên herêmî de wekî xwarinek zebze ya bi tomato an goşt gelemperî ye.', 'Okra di xwarinên herêmî de wekî xwarinek zebze ya bi tomato an goşt gelemperî ye.', 'Bamya, domatesli veya etli sebze yemeği olarak bölgesel mutfaklarda yaygındır.', 'C'),
('48baf8ff-6040-4826-8b61-3461c5daac58', 'Biryanî bi gelemperî di pêjgeha Kurdistanê û iraqî de bi kîjan malzemeya sereke ve tê girêdan?', 'Biryanî xwarinek herêmî ye ku ji birinc, goşt û biharatan pêk tê.', 'Biryanî xwarinek herêmî ye ku ji birinc, goşt û biharatan pêk tê.', 'Biryani, pirinç, et ve baharatların birlikte kullanıldığı bölgesel bir yemektir.', 'A'),
('4932a183-cb26-4ee7-a103-75ec5a424e70', 'Peyva "bajar" bi Tirkî tê wateya "şehir".', 'Wekheviya rast ji bo "bajar" "şehir" e.', 'Wekheviya rast ji bo "bajar" "şehir" e.', '"bajar" için doğru karşılık "şehir"tir.', 'A'),
('4966368d-5586-4727-979b-adbb43065ac4', 'Di helbestên Feqiyê Teyran de kîjan motîf gelek caran hatiye bikaranîn?', 'Xweza û motîfên çûkan di helbestên Feqiyê Teyran (teyr = çûk) de derdikeve pêş.', 'Xweza û motîfên çûkan di helbestên Feqiyê Teyran (teyr = çûk) de derdikeve pêş.', 'Feqiyê Teyran''ın şiirlerinde doğa ve kuş motifleri öne çıkar (teyr = kuş).', 'C'),
('497fa3c6-1cf9-4f49-b0de-4f4b09edd1c3', 'Kîjan pêvajo di qelsbûna mîrnişînên kurdan de di sedsala 19an de diyarker bû?', 'Mîrnişînên wek Baban, Botan û Soran di nav navendîbûna împeratorî û hevrikiyên herêmî de kêm bûne.', 'Mîrnişînên wek Baban, Botan û Soran di nav navendîbûna împeratorî û hevrikiyên herêmî de kêm bûne.', 'Baban, Botan ve Soran gibi emirlikler, imparatorluk merkezileşmesi ve bölgesel rekabetler içinde geriledi.', 'B'),
('49b6c8ec-7565-4dcb-9584-cc5acd6199c4', '"Lorî" çi ye?', '"lorî" lûleyek e ku ji bo razanê pitikan tê gotin.', '"lorî" lûleyek e ku ji bo razanê pitikan tê gotin.', '"lorî" bebekleri uyutmak için söylenen ninnidir.', 'A'),
('49ca3017-5db3-4df7-8361-abf8c414a7e3', '"Mukriyan" û "Erdelan" ji hêla dîrokî ve bi kîjan herêmê ve girêdayî ne?', 'Mukriyan û Erdelan di nav sînorên Îrana îroyîn de herêmên kurdî yên (Rojhilat) ne.', 'Mukriyan û Erdelan di nav sînorên Îrana îroyîn de herêmên kurdî yên (Rojhilat) ne.', 'Mukriyan ve Erdelan, bugünkü İran sınırları içindeki (Doğu) Kürt bölgeleridir.', 'A'),
('49d58758-8f7c-4f09-8e1a-38026854865a', 'Peyva "Dengbêj" ji kîjan du kokan pêk tê?', 'Ji rehên "Dengbêj", "deng" (deng) û "bêj" (axêver) pêk tê: yê ku bi deng/bi devkî diaxive.', 'Ji rehên "Dengbêj", "deng" (deng) û "bêj" (axêver) pêk tê: yê ku bi deng/bi devkî diaxive.', '"Dengbêj", "deng" (ses) ve "bêj" (söyleyen) köklerinden oluşur: sesle/sözle söyleyen.', 'C'),
('49e3ccfb-8302-4cbe-9997-a5c13ca1717a', 'Di serdema Selaheddîn de Eyûbiyan kîjan tevgera olî xurt kir?', 'Di serdema Selahedîn de Eyûbiyan polîtîkayên ku Îslama Sunnî xurtir kirin meşandin.', 'Di serdema Selahedîn de Eyûbiyan polîtîkayên ku Îslama Sunnî xurtir kirin meşandin.', 'Selahaddin Eyyubi döneminde Eyyubiler, Sünni İslam''ı güçlendiren politikalar izlemiştir.', 'C'),
('49efb065-b996-467b-869e-25796782b2cb', 'Têgeha "öz savunma" di paradîgmayê de di warê sivîl de tê çi wateyê?', 'Xweparastin, di wateya medenî de, mafê civakê ye ku hebûna xwe û nirxên xwe biparêze û birêxistin bike.', 'Xweparastin, di wateya medenî de, mafê civakê ye ku hebûna xwe û nirxên xwe biparêze û birêxistin bike.', 'Öz savunma, sivil anlamda toplumun kendi varlığını ve değerlerini koruma-örgütleme hakkını ifade eder.', 'D'),
('4a080046-b986-4ac4-946f-9a42dd4efb2f', 'Selaheddîn herî zêde bi kîjan têkoşînê tê bibîranîn?', 'Selaheddîn bi şerê xwe yê li dijî Seferên Xaçperestan tê naskirin.', 'Selaheddîn bi şerê xwe yê li dijî Seferên Xaçperestan tê naskirin.', 'Selahaddin Eyyubi, Haçlı seferlerine karşı verdiği mücadeleyle tanınır.', 'B'),
('4a2eb360-1bfe-4df6-98ac-992d81a75ed7', '"Êlih" navê kurdî yê kîjan bajarî ye?', '"Êlih" navê kurdî yê bajarê Batmanê ye.', '"Êlih" navê kurdî yê bajarê Batmanê ye.', '"Êlih", Batman şehrinin Kürtçe adıdır.', 'D'),
('4a3662b1-5f24-4d6f-9584-36e1c7c9ae45', 'Yek ji cudahiyên rêzimanî yên sereke di navbera Kurmancî û Soranî de çi ye?', 'Kurmancî cihêrengiya nêr/mê di navdêran de diparêze, soranî bi giranî ev cudahî winda kiriye.', 'Kurmancî cihêrengiya nêr/mê di navdêran de diparêze, soranî bi giranî ev cudahî winda kiriye.', 'Kurmancî isimlerde eril/dişil ayrımını korurken Soranî bu ayrımı büyük ölçüde yitirmiştir.', 'D'),
('4a43afd6-6fe6-44b6-b082-a5872bbbe3bf', 'Di lêkolîna dîroka Kurd û Kurdistanê de dîroka devkî çi tê wateyê?', 'Dîroka devkî dikare di lêkolîna dîroka Kurd û Kurdistanê de weke rêbazeke têgihîştina rabirdûyê bi şahidî û vegotinan were bikaranîn.', 'Dîroka devkî dikare di lêkolîna dîroka Kurd û Kurdistanê de weke rêbazeke têgihîştina rabirdûyê bi şahidî û vegotinan were bikaranîn.', 'sözlü tarih, Kürt ve Kürdistan tarihi araştırmalarında tanıklık ve anlatılarla geçmişi anlama yöntemi olarak kullanılabilir.', 'B'),
('4a484b38-5b44-47e1-a208-ec138afc7a07', 'Alfabeya Kurmancî ya Latînî kê amade kir?', 'Bedirxan alfabeya kurmanciya latînî ya ku îro tê bikaranîn organîze kir.', 'Bedirxan alfabeya kurmanciya latînî ya ku îro tê bikaranîn organîze kir.', 'Bugün kullanılan Latin temelli Kurmanci alfabesini Bedirxan düzenledi.', 'A'),
('4a5315ea-60c5-4add-95b5-c6864931e649', 'Di Kurmancî de peyva "îro" bi Tirkî çi ye?', 'Peyva "îro" tê wateya "bugün".', 'Peyva "îro" tê wateya "bugün".', '"îro" kelimesi "bugün" anlamına gelir.', 'D'),
('4aa3b08d-0eb9-48eb-b8a9-31c011a4f0ed', 'Di çanda kurdî de gelek caran lorandin çi fonksiyonê dikin?', 'Di şînê de bîranîna bûyerên civakî û êşên kolektîf, her wiha şîna ferdî pêk tê.', 'Di şînê de bîranîna bûyerên civakî û êşên kolektîf, her wiha şîna ferdî pêk tê.', 'Ağıtlar, bireysel yasın yanında toplumsal olayların ve kolektif acının hafızasını taşır.', 'B'),
('4aae138e-7828-4650-a573-59db5d054575', 'Hevoka "Kal û pîr" kê diyar dike?', 'Hevoka "Kal û pîr" kal û pîran vedibêje.', 'Hevoka "Kal û pîr" kal û pîran vedibêje.', '"Kal û pîr" deyimi yaşlıları/ihtiyarları anlatır.', 'A'),
('4ac73280-4441-4506-8472-1632a46c2531', '"Mereş" navê kurdî yê kîjan bajarî ye?', '"Mereş" navê kurdî yê bajarê Kahramanmaraşê ye.', '"Mereş" navê kurdî yê bajarê Kahramanmaraşê ye.', '"Mereş", Kahramanmaraş şehrinin Kürtçe adıdır.', 'B'),
('4ac99947-4c8c-4f6c-9f95-42d98d7056e8', 'Ji yên jêrîn kîjan kes bi edebiyata Kurdî re tê girêdan?', 'Navê hilbijartî yek ji navên naskirî ye di çarçoveya edebiyata kurdî de.', 'Navê hilbijartî yek ji navên naskirî ye di çarçoveya edebiyata kurdî de.', 'Seçilen isim Kürt edebiyatı bağlamında bilinen isimlerdendir.', 'A'),
('4ae40ab0-7a3f-49e5-9d5f-57717cd33726', 'Di Kurmancî de "çar" kîjan hejmar e?', '"Çar" bi Tirkî tê wateya "dört".', '"Çar" bi Tirkî tê wateya "dört".', null, 'A'),
('4b5edffd-aaeb-47e7-8112-ee931ec6880f', 'Di Kurmancî de wateya "pirs" çi ye?', '"Pirs" tê wateya pirsê; Ew di mijara serîlêdanê de digel "Pêşbirk" (pêşbazî) cih digire.', '"Pirs" tê wateya pirsê; Ew di mijara serîlêdanê de digel "Pêşbirk" (pêşbazî) cih digire.', '"Pirs" soru demektir; "Pêşbirk" (yarışma) ile birlikte uygulamanın temasında geçer.', 'C'),
('4bda3721-2e8b-4fc0-987f-9ddbded04cfb', 'Çima amadekarî û zuwakirina zivistanê di jiyana kevneşopî ya kurdan de girîng e?', 'Di şert û mercên çiyayî û demsalî de zuwakirin, depokirin û amadekariyên zivistanê ji bo aboriya malê girîng in.', 'Di şert û mercên çiyayî û demsalî de zuwakirin, depokirin û amadekariyên zivistanê ji bo aboriya malê girîng in.', 'Dağlık ve mevsimsel koşullarda kurutma, saklama ve kışlık hazırlıklar hane ekonomisi için önemlidir.', 'A'),
('4bf32144-8dcb-45e1-b2b3-7180b210b772', 'Di edebiyata Kurdî de destan çi tê wateyê?', 'Destan di warê edebiyata kurdî de bi wateya vegotina lehengiyê tê bikaranîn.', 'Destan di warê edebiyata kurdî de bi wateya vegotina lehengiyê tê bikaranîn.', 'destan, Kürt edebiyatı alanında kahramanlık anlatısı anlamında kullanılır.', 'A'),
('4c0f2eed-7ce6-410e-a713-c8aa7b2931be', 'Kîjan herêm bi tevgera "Koçgiri" (1921) ve girêdayî ye?', 'Tevgera Koçgirî (1921) tevgereke kurd e ku bi hawîrdora xwe ya Sêwas-Dêrsimê tê naskirin.', 'Tevgera Koçgirî (1921) tevgereke kurd e ku bi hawîrdora xwe ya Sêwas-Dêrsimê tê naskirin.', 'Koçgiri hareketi (1921), Sivas-Dersim çevresiyle anılan bir Kürt hareketidir.', 'C'),
('4c682b0c-a048-4f56-a184-9599c0bb61de', 'Bajarê Mehabadê îro li kîjan welatî ye?', 'Mehabad bajarekî li rojavayê Îranê ye ku di warê dîroka kurdan de xwedî girîngiyeke sembolîk e.', 'Mehabad bajarekî li rojavayê Îranê ye ku di warê dîroka kurdan de xwedî girîngiyeke sembolîk e.', 'Mahabad, İran’ın batısında Kürt tarihi açısından sembolik önemi olan bir kenttir.', 'B'),
('4c6d487b-5198-4ecf-a1d4-8985e299ce01', 'Di ala kurdî de sê rengên bingehîn çi ne?', 'Ala kurdî bi rengên sor, spî û kesk û rojek li naverastê ye.', 'Ala kurdî bi rengên sor, spî û kesk û rojek li naverastê ye.', 'Kürt bayrağında kırmızı, beyaz ve yeşil renkler ile ortada bir güneş bulunur.', 'D'),
('4c800550-6c60-42f6-9785-75c5634d451e', 'Peyva "hesp" bi Tirkî tê wateya "aslan".', 'Peyva "hesp" tê wateya "at".', 'Peyva "hesp" tê wateya "at".', '"hesp" kelimesi "at" demektir.', 'B'),
('4cab2db5-9b59-4be6-a219-82a892019bf1', '"Wêranşar" navê kurdî yê kîjan wargehê ye?', '"Wêranşar" navê Kurdî yê Wêranşara Şanliurfayê ye.', '"Wêranşar" navê Kurdî yê Wêranşara Şanliurfayê ye.', '"Wêranşar", Şanlıurfa''ya bağlı Viranşehir''in Kürtçe adıdır.', 'C'),
('4d90fa88-190f-415a-989a-63eb5e428204', 'Dehak di efsaneya Newrozê de weke kesekî çawa tê binavkirin?', 'Di çîroka Newrozê de Dehak weke şah/zalimekî zalim ku li gel zilmê dike hatiye nîşandan.', 'Di çîroka Newrozê de Dehak weke şah/zalimekî zalim ku li gel zilmê dike hatiye nîşandan.', 'Newroz anlatısında Dehak, halka zulmeden zalim bir kral/tiran olarak betimlenir.', 'C'),
('4db4321e-37c5-4fc9-938e-f874d64fc330', 'Yekemîn rojnameya kurdî "Kurdistan" (1898) cara pêşî li ku derket?', 'Yekemîn rojnameya kurdî Kurdistan di sala 1898an de li Qahîreyê dest bi weşanê kir.', 'Yekemîn rojnameya kurdî Kurdistan di sala 1898an de li Qahîreyê dest bi weşanê kir.', 'İlk Kürtçe gazete Kurdistan, 1898''de Kahire''de yayımlanmaya başlamıştır.', 'B'),
('4dc390b5-5655-48f2-8f28-ccaf9a837184', 'Mistefa Barzanî yek ji serokên kîjan tevgerê ye?', 'Mistefa Barzanî yek ji pêşengên tevgera neteweyî ya kurdên Iraqê ya sedsala 20an e.', 'Mistefa Barzanî yek ji pêşengên tevgera neteweyî ya kurdên Iraqê ya sedsala 20an e.', 'Mustafa Barzani, 20. yüzyıl Irak Kürt ulusal hareketinin önde gelen önderlerindendir.', 'A'),
('4dcb850c-c714-41cf-9279-d380c124f79f', 'Helwesta bingehîn ku jiyana hevpar di "Demokratik ulus" de gengaz dike çi ye?', 'Di neteweya demokratîk de jiyana hevpar li ser esasê rêzgirtina cudahiyan û wekheviyê pêkan e.', 'Di neteweya demokratîk de jiyana hevpar li ser esasê rêzgirtina cudahiyan û wekheviyê pêkan e.', 'Demokratik ulusta ortak yaşam, farklılıklara saygı ve eşitlik temelinde mümkün olur.', 'B'),
('4e0cd665-f968-4947-a5f8-16420f722105', 'Bedirxaniyan (Bedirxan Beyan) bi kîjan bajarî tên naskirin?', 'Bedirxan Beyan di sedsala 19. de bi mîrektiya Cizîr-Bohtan hatiye naskirin.', 'Bedirxan Beyan di sedsala 19. de bi mîrektiya Cizîr-Bohtan hatiye naskirin.', 'Bedirxan Beyleri, 19. yüzyılda Cizre-Bohtan beyliğiyle özdeşleşmiştir.', 'A'),
('4e48396f-f10a-4a25-810a-a1a6772262ab', 'Di lêkolîna dîroka Kurd û Kurdistanê de arkeolojî çi tê wateyê?', 'Ew dikare ji bo lêkolîna paşerojê bi bermahiyên maddî yên di arkeolojî, lêkolînên dîroka kurd û Kurdistanê de were bikar anîn.', 'Ew dikare ji bo lêkolîna paşerojê bi bermahiyên maddî yên di arkeolojî, lêkolînên dîroka kurd û Kurdistanê de were bikar anîn.', 'arkeoloji, Kürt ve Kürdistan tarihi araştırmalarında maddi kalıntılarla geçmişi araştırma olarak kullanılabilir.', 'A'),
('4e4f4b7c-3a9e-41eb-ae05-0cf178b183ca', 'Di derbarê pîrozbahîya cejnê de kîjan rasttir e?', 'Pîrozbahiyên eydê di çanda kurdî de bi qada hecê ve girêdayî ye.', 'Pîrozbahiyên eydê di çanda kurdî de bi qada hecê ve girêdayî ye.', 'bayramlaşma, Kürt kültüründe ziyaret alanıyla bağlantılıdır.', 'A'),
('4e61e25f-888e-4ade-b59a-22d11567a3bf', 'Di Kurmancî de peyva "kanî" bi Tirkî çi ye?', 'Peyva "kanî" tê wateya "çeşme/pınar".', 'Peyva "kanî" tê wateya "çeşme/pınar".', '"kanî" kelimesi "çeşme/pınar" anlamına gelir.', 'A'),
('4e9b1f98-2039-4ecb-bd47-8222f31a3fb3', 'Di Kurmancî de peyva "pîr" bi Tirkî çi ye?', 'Peyva "pîr" tê wateya "yaşlı/ihtiyar".', 'Peyva "pîr" tê wateya "yaşlı/ihtiyar".', '"pîr" kelimesi "yaşlı/ihtiyar" anlamına gelir.', 'A'),
('4ecf4ef1-7d6c-4681-bf61-08e9ab57d29a', 'Di Kurmancî de peyva "kar" bi Tirkî çi ye?', 'Peyva "kar" tê wateya "iş".', 'Peyva "kar" tê wateya "iş".', '"kar" kelimesi "iş" anlamına gelir.', 'C'),
('4f0baced-b1c9-44d2-a4dc-ad5d812d28d3', '"Demokratik modernite" li ser kîjan nirxan e?', 'Modernîteya Demokratîk; Li ser esasê nirxên demokrasî, azadiya jinê û ekolojiyê ye.', 'Modernîteya Demokratîk; Li ser esasê nirxên demokrasî, azadiya jinê û ekolojiyê ye.', 'Demokratik modernite; demokrasi, kadın özgürlüğü ve ekoloji değerlerini esas alır.', 'A'),
('4fafabdb-d1cb-4c8d-8f8b-de897c8349ae', 'Di Kurmancî de peyva "mal" bi Tirkî çi ye?', 'Peyva "mal" tê wateya "ev".', 'Peyva "mal" tê wateya "ev".', '"mal" kelimesi "ev" anlamına gelir.', 'C'),
('4fb19663-126e-4a0f-95fd-d95a7644eab0', 'Daxwaza perwerdeya bi zimanê dayikê di kîjan kategoriyê de rast e?', 'Perwerdeya bi zimanê dayikê di bin navê mafên çandî û zimanî de tê nirxandin.', 'Perwerdeya bi zimanê dayikê di bin navê mafên çandî û zimanî de tê nirxandin.', 'Anadilde eğitim, kültürel ve dilsel haklar başlığı altında değerlendirilir.', 'C'),
