('52f5aba0-3701-454c-a3eb-1e05b26cbff6', 'Wateya lêkera "hatin" di kurmancî de çi ye?', '"Hatin" bi Tirkî tê wateya "gelmek".', '"Hatin" bi Tirkî tê wateya "gelmek".', null, 'B'),
('5336eaa3-837f-427e-8a33-d301f500523c', '"Stenbol" bilêvkirina kurdî ya kîjan bajarî ye?', '"Stenbol" bilêvkirina kurdî ya Stenbolê ye.', '"Stenbol" bilêvkirina kurdî ya Stenbolê ye.', '"Stenbol", İstanbul''un Kürtçe söylenişidir.', 'A'),
('53387b0e-faf9-4a51-9353-de3bec45337f', 'Ehmedê Xanî bi çi armancê dibêje Mem û Zîn nivîsiye?', 'Ehmedê Xanî jî armanca xwe di xebata xwe de bilêvkirina nirxa zimanê kurdî û yekitiya kurdî tîne ziman.', 'Ehmedê Xanî jî armanca xwe di xebata xwe de bilêvkirina nirxa zimanê kurdî û yekitiya kurdî tîne ziman.', 'Ehmedê Xanî, eserinde Kürtçenin ve Kürt birliğinin değerini vurgulama amacını da dile getirir.', 'B'),
('534ae4f3-04d4-430b-98fb-5866c10bb3d4', 'Di çanda gelêrî ya Kurdan de girîngiya ku ji çiyan re tê dayîn çi rave dike?', 'Girîngiya kurdan bi çiyayan ve girêdayî ye ku di dirêjahiya dîrokê de li erdnîgariyeke çiyayî jiyaye.', 'Girîngiya kurdan bi çiyayan ve girêdayî ye ku di dirêjahiya dîrokê de li erdnîgariyeke çiyayî jiyaye.', 'Kürtlerin dağlara verdiği önem, tarih boyunca dağlık bir coğrafyada yaşamalarıyla ilişkilidir.', 'C'),
('535ccc09-f04f-4e99-95f7-f59a31716d6f', 'Herêma ku Kurd lê dijîn bi giştî li kîjan herêma avhewayê ye?', 'Li herêmê avhewaya bi piranî parzemînî û çiyayî heye.', 'Li herêmê avhewaya bi piranî parzemînî û çiyayî heye.', 'Bölge, ağırlıkla karasal ve dağlık bir iklime sahiptir.', 'B'),
('5364aab9-bed4-4938-966e-1b37451afede', '"ap/apê" di çanda kurdî de tê çi wateyê?', '"Ap/apê" tê wateya mamê (mînak Apê Musa).', '"Ap/apê" tê wateya mamê (mînak Apê Musa).', '"Ap/apê" amca demektir (ör. Apê Musa).', 'B'),
('53983b7c-76f5-4b52-86fc-f15f09a832c8', '"Semsûr" navê kurdî yê kîjan bajarî ye?', '"Semsûr" navê kurdî yê bajarê Adiyamanê ye.', '"Semsûr" navê kurdî yê bajarê Adiyamanê ye.', '"Semsûr", Adıyaman şehrinin Kürtçe adıdır.', 'A'),
('53b27cdd-03a2-4624-8f79-740682b53c1e', '"Euphrates" navekî din ê kîjan çemî ye?', '"Euphrates" navê (navneteweyî) çemê Firatê ye.', '"Euphrates" navê (navneteweyî) çemê Firatê ye.', '"Euphrates", Fırat Nehri''nin (uluslararası) adıdır.', 'D'),
('53bcde96-5a31-48db-b31b-2556c73936c1', '"Gotinên pêşiyan" bi Tirkî çi ne?', '"Gotinên pêşiyan" (peyvên berê) gotinên pêşiyan in.', '"Gotinên pêşiyan" (peyvên berê) gotinên pêşiyan in.', '"Gotinên pêşiyan" (öncekilerin sözleri) atasözleridir.', 'A'),
('53e806cc-892e-418f-9aba-00f9aebe7f3c', 'hewa yek ji têgehên ji bo têgihîştina erdnîgariya Kurdistanê ye.', 'Erdnîgarî jîngeha xwezayî û mirovan lêkolîn dike.', 'Erdnîgarî jîngeha xwezayî û mirovan lêkolîn dike.', 'Coğrafya doğal ve beşeri çevreyi inceler.', 'A'),
('540d24fa-d381-4d84-8dbd-a5f6d1cb8ae0', 'Kî ye ji pêşengên romana kurdî ya nûjen, nivîskarê ku berhemên wek "Bîra Qederê" nivîsandiye?', 'Mehmed Uzun yek ji pêşengên romana kurdî ya nûjen (Bîra Qederê û hwd.) tê dîtin.', 'Mehmed Uzun yek ji pêşengên romana kurdî ya nûjen (Bîra Qederê û hwd.) tê dîtin.', 'Mehmed Uzun, modern Kürt romanının öncülerinden sayılır (Bîra Qederê vb.).', 'D'),
('54487ed5-6fa5-4e68-9d5d-43e0609deb3e', 'Ramana "Toplumsal ekoloji" li ser çi têkiliyek disekine?', 'Ekolojiya civakî li ser girêdana di navbera têkiliyên serdestiya di civakê de û tunekirina xwezayê disekine.', 'Ekolojiya civakî li ser girêdana di navbera têkiliyên serdestiya di civakê de û tunekirina xwezayê disekine.', 'Toplumsal ekoloji, toplumdaki tahakküm ilişkileri ile doğanın tahribi arasındaki bağı merkeze alır.', 'A'),
('548995d1-81bb-49ac-8233-511c2daa8ec5', 'Di erdnîgariya Kurdistanê de peyva "deşt" bi Tirkî çi ye?', '"deşt" di çarçoveya erdnîgariyê de tê wateya "ova".', '"deşt" di çarçoveya erdnîgariyê de tê wateya "ova".', '"deşt" coğrafya bağlamında "ova" anlamına gelir.', 'A'),
('5498e412-6a45-48f0-bb41-b59437dc65a5', '"Zivistan" kîjan demsal e?', '"zivistan" zivistan e.', '"zivistan" zivistan e.', '"zivistan" kış mevsimidir.', 'A'),
('54b56c74-e5cf-49c9-9663-bac6a2b46727', 'Peyva "kevin" bi Tirkî tê wateya "erken".', '"kevin" tê wateya "eski"; "zû" tê wateya "erken".', '"kevin" tê wateya "eski"; "zû" tê wateya "erken".', '"kevin" "eski" demektir; "zû" ise "erken" anlamına gelir.', 'B'),
('54eda4c6-6ac6-40d2-b15d-be32c6dac5bd', 'Kurdîya soranî li Iraq û Îranê bi piranî di kîjan sîstema nivîsandinê de tê nivîsandin?', 'Soranî li Iraq û Îranê pir bi alfabeya kurdî ya erebî tê nivîsandin.', 'Soranî li Iraq û Îranê pir bi alfabeya kurdî ya erebî tê nivîsandin.', 'Soranî, Irak ve İran’da Arap temelli Kürt alfabesiyle yaygın biçimde yazılır.', 'A'),
('551d77a5-e18d-4b8d-8800-2ad79eac6d07', '"Demokratik özerklik" ji nêz ve bi kîjan têgînê ve girêdayî ye?', 'Xweseriya Demokratîk ji nêz ve bi feraseta xwerêveberiya herêmî ve girêdayî ye.', 'Xweseriya Demokratîk ji nêz ve bi feraseta xwerêveberiya herêmî ve girêdayî ye.', 'Demokratik özerklik, yerel öz yönetim kavramıyla yakından ilişkilidir.', 'C'),
('55dc1ff1-bcb2-4b9c-b905-d5d8acc2178f', 'Di Kurmancî de "pênc" kîjan hejmar e?', '"Pênc" bi Tirkî tê wateya "beş".', '"Pênc" bi Tirkî tê wateya "beş".', null, 'B'),
('55ebe80a-e547-4685-a15e-6938e625edd4', 'Peyva "deng" bi Tirkî tê wateya "ses".', 'Wekheviya rast ji bo "deng" "ses" e.', 'Wekheviya rast ji bo "deng" "ses" e.', '"deng" için doğru karşılık "ses"tir.', 'A'),
('55fd58e1-eb8f-4ae4-b1fd-30e5f1cec2dc', 'Di modela xweseriya demokratîk de bi giranî biryar li ku tên girtin?', 'Di xweseriya demokratîk de biryar ji jêr ve bi rêya meclîsên herêmî û komunan tên girtin.', 'Di xweseriya demokratîk de biryar ji jêr ve bi rêya meclîsên herêmî û komunan tên girtin.', 'Demokratik özerklikte kararlar, yerel meclis ve komünler aracılığıyla tabandan alınır.', 'A'),
('5605aac5-b055-43d7-aba7-248b17067c82', 'Zimanê çareseriya piralî û demokratîk çi esas digire?', 'Zimanê çareseriya piralî pêşîya diyalog û muzakereyê dide zorê û ferzkirinê.', 'Zimanê çareseriya piralî pêşîya diyalog û muzakereyê dide zorê û ferzkirinê.', 'Çoğulcu çözüm dili, güç ve dayatma yerine diyalog ve müzakereyi önceler.', 'B'),
('567e414a-8913-498c-8c6d-69e4ee14ea6a', 'Peyva "ciwan" bi Tirkî tê wateya "genç".', 'Wekheviya rast ji bo "ciwan" "genç" e.', 'Wekheviya rast ji bo "ciwan" "genç" e.', '"ciwan" için doğru karşılık "genç"tir.', 'A'),
('56ae5d95-61ef-45b1-aa14-45686727ce4c', 'Di Kurmancî de wateya "dost" çi ye?', '"Dost" bi Tirkî tê wateya "dost/arkadaş".', '"Dost" bi Tirkî tê wateya "dost/arkadaş".', null, 'B'),
('56d94be4-3036-4be4-b476-cfbfb216ee6a', '"Dohuk" (Duhok) li kîjan welatî ye?', 'Dihok (Duhok) bajarekî Herêma Kurdistana Iraqê ye.', 'Dihok (Duhok) bajarekî Herêma Kurdistana Iraqê ye.', 'Dohuk (Duhok), Irak Kürdistan Bölgesi''nde bir şehirdir.', 'A'),
('57a05712-54f2-45fc-b91c-56d1b0080041', 'Wateya "Dest" bi Tirkî çi ye?', '"Dest" bi Tirkî tê wateya "el".', '"Dest" bi Tirkî tê wateya "el".', null, 'C'),
('57c17095-790f-44d8-865e-d23e25ed7b19', 'Kîjan çavkanî bi taybetî di derbasbûna ji çanda devkî ber bi romana nûjen di edebiyata kurdî de xwar bû?', 'Di edebiyata kurdî ya nûjen de mîrata devkî ji bo naskirina nasname, cih û ziman wek çavkaniyeke xurt hatiye bikaranîn.', 'Di edebiyata kurdî ya nûjen de mîrata devkî ji bo naskirina nasname, cih û ziman wek çavkaniyeke xurt hatiye bikaranîn.', 'Modern Kürt edebiyatında sözlü miras, kimlik, yer ve dil bilincini taşıyan güçlü bir kaynak olarak kullanılmıştır.', 'B'),
('5844e475-c9c8-49e1-9be8-8a195f14db2e', 'Di edebiyata Kurdî de mecaz çi tê wateyê?', 'Metafor di warê edebiyata kurdî de di wateya vegotina nerasterast de tê bikaranîn.', 'Metafor di warê edebiyata kurdî de di wateya vegotina nerasterast de tê bikaranîn.', 'mecaz, Kürt edebiyatı alanında dolaylı/anlam aktarımlı anlatım anlamında kullanılır.', 'A'),
('5854ecc7-2053-4d7c-9bf1-6a5851a43276', 'Peyva "çûn" bi Tirkî tê wateya "gitmek".', 'Wekheviya rast ji bo "çûn" "gitmek" e.', 'Wekheviya rast ji bo "çûn" "gitmek" e.', '"çûn" için doğru karşılık "gitmek"tir.', 'A'),
('58ebbeed-e60d-4a39-9a49-65003d2875dc', 'Di Kurmancî de peyva "sar" bi Tirkî çi ye?', 'Peyva "sar" tê wateya "soğuk".', 'Peyva "sar" tê wateya "soğuk".', '"sar" kelimesi "soğuk" anlamına gelir.', 'A'),
('5914bc82-d7c7-4b43-acdf-a3d6a3283bcd', 'Wateya peyva kurdî “rengîn” di wesfên çandî de çi ye?', 'Reng, bi wateya xwe ya rengîn, ji bo danasîna cihêrengiya çandî û estetîkê dikare were bikaranîn.', 'Reng, bi wateya xwe ya rengîn, ji bo danasîna cihêrengiya çandî û estetîkê dikare were bikaranîn.', 'Rengîn, renkli anlamıyla kültürel çeşitlilik ve estetik betimlemelerde kullanılabilir.', 'A'),
('59236644-9dbe-49c0-a4d0-16d735457ca2', '"Ekoloji, kadın özgürlüğü ve demokrasi" stûnên kîjan paradîgmayê ne?', 'Ev her sê nirx stûnên bingehîn ên paradîgmaya konfederalîzma demokratîk in.', 'Ev her sê nirx stûnên bingehîn ên paradîgmaya konfederalîzma demokratîk in.', 'Bu üç değer, demokratik konfederalizm paradigmasının temel sütunlarıdır.', 'D'),
('598c5626-6dd1-4540-9ce5-20d399059233', 'Selahedînê Eyûbî ji kîjan gelî tê?', 'Damezrênerê xanedana Eyûbiyan Selaheddîn bi eslê xwe kurd bû.', 'Damezrênerê xanedana Eyûbiyan Selaheddîn bi eslê xwe kurd bû.', 'Eyyubi hanedanının kurucusu Selahaddin Eyyubi Kürt kökenlidir.', 'A'),
('59c0ede1-0614-4726-820a-7139827367db', 'Împaratoriya Medan li kîjan herêmê derket holê?', 'Împaratoriya Medyayê li herêma Zagrosê (rojavayê Îranê) hate damezrandin.', 'Împaratoriya Medyayê li herêma Zagrosê (rojavayê Îranê) hate damezrandin.', 'Med İmparatorluğu, Zagros bölgesinde (İran''ın batısı) kuruldu.', 'A'),
('5a0e2248-f33a-4c12-9bcc-f6a0d4de2db2', 'Kîjan yek ji welatên cîranê herêmê ye di danasîna fermî ya Hikûmeta Herêma Kurdistanê de?', 'Di rûpela sermayeguzarî/pêşverû ya Hikûmeta Herêma Kurdistanê de, tekezî li ser pêwendiyên sînorî yên herêmê ligel Tirkiye, Îran û Sûriyê hatiye kirin.', 'Di rûpela sermayeguzarî/pêşverû ya Hikûmeta Herêma Kurdistanê de, tekezî li ser pêwendiyên sînorî yên herêmê ligel Tirkiye, Îran û Sûriyê hatiye kirin.', 'KRG’nin yatırım/tanıtım sayfasında bölgenin Türkiye, İran ve Suriye ile sınır ilişkisi vurgulanır.', 'B'),
('5a353fdc-81c5-489f-a131-4cb9c13d0087', 'Peyva "spas" bi Tirkî tê wateya "güzel/iyi".', 'Peyva "spas" tê wateya "teşekkür".', 'Peyva "spas" tê wateya "teşekkür".', '"spas" kelimesi "teşekkür" demektir.', 'B'),
('5a870e5d-4c05-4f20-b106-06fdab29af32', 'Cejna Newroz û biharê herî zêde çi temayê li hev dikin?', 'Newroz û pîrozbahiyên biharê mijara vejîn û pirbûna xwezayê parve dikin.', 'Newroz û pîrozbahiyên biharê mijara vejîn û pirbûna xwezayê parve dikin.', 'Newroz ve bahar kutlamaları, doğanın yeniden canlanışı ve bereket temasını paylaşır.', 'C'),
('5a8a5985-7da7-4c75-a150-ce9f00f475b8', '"Def û zirne" bi gelemperî li ku tên lêdan?', 'Def û bilûr muzîka dawet û şahiyan e.', 'Def û bilûr muzîka dawet û şahiyan e.', 'Davul-zurna düğün ve şenliklerin müziğidir.', 'A'),
('5a8c4971-5065-4d4f-aff1-4740385bbe68', 'Kîjan vebijark girîngiya paradîgmayê ya li ser “çoğulculuk” çêtirîn diyar dike?', 'Pirrjimarî ramana jiyana hevpar e ku mafên Ereb, Suryanî, Ermenî, Tirkmen, Êzidî û civakên din û her wiha Kurdan jî dihewîne.', 'Pirrjimarî ramana jiyana hevpar e ku mafên Ereb, Suryanî, Ermenî, Tirkmen, Êzidî û civakên din û her wiha Kurdan jî dihewîne.', 'Çoğulculuk, Kürtlerin yanı sıra Arap, Süryani, Ermeni, Türkmen, Ezidi ve diğer toplulukların haklarını da içeren ortak yaşam fikridir.', 'A'),
('5a99064b-45ab-4c8f-b030-2a86b3e4b4a6', 'Peyva "xwendin" bi Tirkî tê wateya "yazmak".', 'Peyva "xwendin" tê wateya "okumak".', 'Peyva "xwendin" tê wateya "okumak".', '"xwendin" kelimesi "okumak" demektir.', 'B'),
('5aa90807-eb18-440d-8d76-661ce1ad71ec', 'Di muzîka Kurdî de ritim bi çi re têkildar e?', 'rîtm di warê muzîka kurdî de bi lêdana rêkûpêk ve girêdayî ye.', 'rîtm di warê muzîka kurdî de bi lêdana rêkûpêk ve girêdayî ye.', 'ritim, Kürt müziği alanında düzenli vuruş ile ilişkilidir.', 'A'),
('5ae2e34e-67e5-42a3-b31f-0a3eecd01978', 'Di Kurmancî de peyva "por" bi Tirkî çi ye?', 'Peyva "por" tê wateya "saç".', 'Peyva "por" tê wateya "saç".', '"por" kelimesi "saç" anlamına gelir.', 'C'),
('5b10c996-aa99-4381-93df-8c9b6937d43b', '"Tembûr" çi celeb amûr e?', 'Tembûr amûreke têl bi stûyê dirêj e.', 'Tembûr amûreke têl bi stûyê dirêj e.', 'Tembûr, uzun saplı telli bir çalgıdır.', 'D'),
('5b25cc7a-070b-4d1b-a6bf-74db88616aa6', 'Di Kurmancî de "şeş" kîjan hejmar e?', '"Şeş" bi Tirkî tê wateya "altı".', '"Şeş" bi Tirkî tê wateya "altı".', null, 'B'),
('5baa0dcb-18f4-488b-ab1d-1b40fd6f4481', 'Peyva "kar" bi Tirkî tê wateya "sanat".', 'Peyva "kar" tê wateya "iş".', 'Peyva "kar" tê wateya "iş".', '"kar" kelimesi "iş" demektir.', 'B'),
('5bf2ec75-3a8d-42bf-aef0-74c3af8d18ca', 'Peyva "biçûk" bi Tirkî tê wateya "küçük".', 'Wekheviya rast ji bo "biçûk" "küçük" e.', 'Wekheviya rast ji bo "biçûk" "küçük" e.', '"biçûk" için doğru karşılık "küçük"tir.', 'A'),
('5c1f615a-a3a8-4d6c-83c4-6a2d562fda35', 'Di erdnîgariya Kurdistanê de avhewa, şînkatî û teşeyên rûerdê girîng in.', 'Ev mijar di nav dersên bingehîn ên erdnîgariyê de ne.', 'Ev mijar di nav dersên bingehîn ên erdnîgariyê de ne.', 'Bu başlıklar coğrafyanın temel konularındandır.', 'A'),
('5cb86d1e-f1f8-4316-ba4f-947761a8302f', 'Peyva "kurd" bi Tirkî tê wateya "Kürt".', 'Wekheviya rast ji bo "kurd" "Kürt" e.', 'Wekheviya rast ji bo "kurd" "Kürt" e.', '"kurd" için doğru karşılık "Kürt"tir.', 'A'),
('5cbdef14-d280-45fd-8db4-cf5da5113e7f', 'Melayê Cizîrî di kîjan kevneşopiya edebî de tê bîranîn?', 'Melayê Cizîrî di nav navên girîng ên helbesta kurdî ya klasîk de tê hesibandin.', 'Melayê Cizîrî di nav navên girîng ên helbesta kurdî ya klasîk de tê hesibandin.', 'Melayê Cizîrî, klasik Kürt şiirinin önemli isimleri arasında sayılır.', 'A'),
('5d144793-68b7-4a62-a8b1-9599ec9f159b', 'Peyva "rast" bi Tirkî tê wateya "yanlış".', '"rast" tê wateya "doğru"; "şaş" tê wateya "yanlış".', '"rast" tê wateya "doğru"; "şaş" tê wateya "yanlış".', '"rast" "doğru" demektir; "şaş" ise "yanlış" anlamına gelir.', 'B'),
('5d19223a-bb9d-44a8-991b-572c29638758', 'Komara Mehabadê ku di sala 1946an de hat damezrandin, di nav sînorên kîjan welatî de bû?', 'Komara Mehabadê di sala 1946an de, di nav sînorên Îrana îroyîn de hat damezrandin.', 'Komara Mehabadê di sala 1946an de, di nav sînorên Îrana îroyîn de hat damezrandin.', 'Mahabad Cumhuriyeti 1946''da, bugünkü İran sınırları içinde kurulmuştur.', 'D'),
('5d2844b2-0214-489a-8174-979f6f06a3fa', '"Demokratik ulus" li ser kîjan têgihîştina nasnameyê ye?', 'Neteweya demokratîk ne li ser yek nasnameyeke etnîkî/olî, li ser têgihiştineke piralî û berfireh a nasnameyê ava bûye.', 'Neteweya demokratîk ne li ser yek nasnameyeke etnîkî/olî, li ser têgihiştineke piralî û berfireh a nasnameyê ava bûye.', 'Demokratik ulus, tek bir etnik/dinî kimliğe değil, çoğul ve kapsayıcı bir kimlik anlayışına dayanır.', 'A'),
('5d70bd04-566f-40f0-a3ca-c7431ff494d6', 'Peyva "ziman" bi Tirkî tê wateya "dil".', 'Wekheviya rast ji bo "ziman" "dil" e.', 'Wekheviya rast ji bo "ziman" "dil" e.', '"ziman" için doğru karşılık "dil"tir.', 'A'),
('5d886719-e2b3-496b-ae26-c80f12ead512', '"Hamidiye Alayları" di dema kîjan sultanî de hatiye damezrandin?', 'Alayên Hemîdiye, bi navê II. Navê xwe ji Abdulhemîd girtiye û di dema desthilatdariya wî de hatiye damezrandin.', 'Alayên Hemîdiye, bi navê II. Navê xwe ji Abdulhemîd girtiye û di dema desthilatdariya wî de hatiye damezrandin.', 'Hamidiye Alayları, adını II. Abdülhamid''den alır ve onun döneminde kurulmuştur.', 'A'),
('5dc04e1b-5b2c-4047-86a0-9505135d24df', 'çavkaniya destpêkê ji bo têgihîştina dîroka Kurd û Kurdistanê dikare were bikaranîn.', 'Çavkaniya bingehîn ji bo ramana dîrokî têgehek kêrhatî ye.', 'Çavkaniya bingehîn ji bo ramana dîrokî têgehek kêrhatî ye.', 'birincil kaynak tarihsel düşünme için yararlı bir kavramdır.', 'A'),
('5e24303e-9ee3-478d-a4e2-be9d649b6c20', 'Di Elewîtiyê de "dede" kî ye?', 'Di Elewîtiyê de, "dede" rêberê olî ye ku rêberiya civakê dike.', 'Di Elewîtiyê de, "dede" rêberê olî ye ku rêberiya civakê dike.', 'Alevilikte "dede", topluluğa yol gösteren dinî önderdir.', 'C'),
('5e263055-944d-414e-93ae-b02013202f0d', 'Di çanda Kurdî de pêjgeha gelêrî bi bîra çandî re têkildar e.', 'Di nav pêjgeha gelêrî, çanda kurdî û hafizeya civakî de wateyek werdigire.', 'Di nav pêjgeha gelêrî, çanda kurdî û hafizeya civakî de wateyek werdigire.', 'halk mutfağı, Kürt kültürü ve toplumsal hafıza içinde anlam kazanır.', 'A'),
('5e4b1d8a-f7bd-4410-aae2-cac2be7571c6', 'Di konfederalîzma demokratîk de çima ekolojî mijareke bingehîn e?', 'Di paradîgmayê de pirsgirêkên civakî bi krîza ekolojîk ve girêdayî ye û girîngiyê dide jiyana herêmî, domdar.', 'Di paradîgmayê de pirsgirêkên civakî bi krîza ekolojîk ve girêdayî ye û girîngiyê dide jiyana herêmî, domdar.', 'Paradigma, sosyal sorunları ekolojik krizle bağlantılı düşünür ve yerel, sürdürülebilir yaşamı vurgular.', 'A'),
('5ec45e07-36ab-470f-8fea-cdfe608b9acb', 'Peyva "mase" bi Tirkî tê wateya "sandalye".', 'Peyva "mase" tê wateya "masa".', 'Peyva "mase" tê wateya "masa".', '"mase" kelimesi "masa" demektir.', 'B'),
('5ec47c97-74c5-4d56-9667-25aec00127bb', '"Mûş" navê kurdî yê kîjan bajarî ye?', '"Mûş" navê kurdî yê bajarê Mûşê ye.', '"Mûş" navê kurdî yê bajarê Mûşê ye.', '"Mûş", Muş şehrinin Kürtçe adıdır.', 'B'),
('5ef929fe-718c-4c04-bc11-e9e21dbebd5e', 'Di Kurmancî de wateya "bajar" çi ye?', '"Bajar" bi Tirkî tê wateya "şehir".', '"Bajar" bi Tirkî tê wateya "şehir".', null, 'B'),
('5f148af5-7c83-4615-86db-fda9a5308fec', 'Yek ji destanên evîna kurdî yên klasîk kîjan e?', 'Siyabend û Xecê, klasik bir Kürt aşk destanıdır.', null, null, 'D'),
('5f491d04-0cfc-4d3d-ba47-0135d996686b', '"Demokratik çözüm" çi nirxan dide pêş?', 'Çareseriya demokratîk; Ew nirxên wekhevî, azadî û aştiyê esas digire.', 'Çareseriya demokratîk; Ew nirxên wekhevî, azadî û aştiyê esas digire.', 'Demokratik çözüm; eşitlik, özgürlük ve barış değerlerini önceler.', 'B'),
('5f5f1dbc-1c5a-4b9d-9518-689c78e336eb', 'Cînavê "hûn" di kurmancî de tê çi wateyê?', '"Hûn" cînavê kesê duyem (tu) yê pirjimar e.', '"Hûn" cînavê kesê duyem (tu) yê pirjimar e.', '"Hûn" ikinci çoğul şahıs (siz) zamiridir.', 'C'),
('5f7ef010-1736-43a6-8ac1-eba16e0647f3', 'Di Kurmancî de wateya "dirêj" çi ye?', '"Dirêj" bi Tirkî tê wateya "uzun".', '"Dirêj" bi Tirkî tê wateya "uzun".', null, 'B'),
('5fb74d03-e889-4410-bd6b-e40e51fd2000', 'Di Kurmancî de "neh" kîjan hejmar e?', '"Neh" bi Tirkî tê wateya "dokuz".', '"Neh" bi Tirkî tê wateya "dokuz".', null, 'B'),
('600ca4ed-833f-4a0e-8f78-f80704e10b93', 'Di Kurmancî de peyva "heval" bi Tirkî çi ye?', 'Peyva "heval" tê wateya "arkadaş".', 'Peyva "heval" tê wateya "arkadaş".', '"heval" kelimesi "arkadaş" anlamına gelir.', 'D'),
('609921e5-f494-452e-b251-12e2b72894ea', 'Peyva "ser" bi Tirkî tê wateya "kulak".', 'Peyva "ser" tê wateya "baş/kafa".', 'Peyva "ser" tê wateya "baş/kafa".', '"ser" kelimesi "baş/kafa" demektir.', 'B'),
('60d2ee3d-e027-48f8-a670-5c9cc47b3e78', 'Di lêkolîna dîroka Kurd û Kurdistanê de çavkaniya destpêkê çi tê wateyê?', 'Di lêkolîna dîroka Kurd û Kurdistanê de dikare wekî çavkaniyek bingehîn, belgeyek rasterast an jî objektek ji serdemê were bikar anîn.', 'Di lêkolîna dîroka Kurd û Kurdistanê de dikare wekî çavkaniyek bingehîn, belgeyek rasterast an jî objektek ji serdemê were bikar anîn.', 'birincil kaynak, Kürt ve Kürdistan tarihi araştırmalarında döneminden kalan doğrudan belge veya nesne olarak kullanılabilir.', 'B')
