('f9d3a308-1bc4-4f8d-8088-a4d9770a0969', 'Di Kurmancî de wateya "çav" çi ye?', '"Çav" bi Tirkî tê wateya "göz".', '"Çav" bi Tirkî tê wateya "göz".', null, 'D'),
('fa404b25-0a8f-40d6-9e61-409ceee5f1aa', 'Peyva "diran" bi Tirkî tê wateya "diş".', 'Wekheviya rast ji bo "diran" "diş" e.', 'Wekheviya rast ji bo "diran" "diş" e.', '"diran" için doğru karşılık "diş"tir.', 'A'),
('fa479f83-ef0f-4df7-9c87-65b5aa6bbbc0', 'Peyva "pir" bi Tirkî tê wateya "başlangıç".', 'Peyva "pir" tê wateya "çok".', 'Peyva "pir" tê wateya "çok".', '"pir" kelimesi "çok" demektir.', 'B'),
('fa5d3161-d503-4ac3-8345-91f20b6df3db', 'Di çanda Kurdî de mêvanperwerî bi bîra çandî re têkildar e.', 'Mêvanperwerî di nav çand û bîra civakî ya Kurdî de wateyek werdigire.', 'Mêvanperwerî di nav çand û bîra civakî ya Kurdî de wateyek werdigire.', 'misafirperverlik, Kürt kültürü ve toplumsal hafıza içinde anlam kazanır.', 'A'),
('fa602931-41dc-4bd6-92fe-4b14ee619395', 'Di projeya "Demokratik ulus" de ferzkirina zimanek hevpar heye?', 'Di neteweya demokratîk de ferzkirina yek zimanî nîne; Pirzimanî û pirzimanî esas in.', 'Di neteweya demokratîk de ferzkirina yek zimanî nîne; Pirzimanî û pirzimanî esas in.', 'Demokratik ulusta tek dil dayatması yoktur; çok dillilik ve çoğulluk esastır.', 'A'),
('faf5e9c5-755e-4255-9816-e1105bd6710d', 'Di çanda Kurdî de govend bi bîra çandî re têkildar e.', 'Govend di nava çand û bîra civakî ya Kurdî de wateyek werdigire.', 'Govend di nava çand û bîra civakî ya Kurdî de wateyek werdigire.', 'govend, Kürt kültürü ve toplumsal hafıza içinde anlam kazanır.', 'A'),
('fbb3217d-6ac5-442a-99c4-dc454f78c6c7', 'Peyva "hezkirin" bi Tirkî tê wateya "sevmek".', 'Wekheviya rast ji bo "hezkirin" "sevmek" e.', 'Wekheviya rast ji bo "hezkirin" "sevmek" e.', '"hezkirin" için doğru karşılık "sevmek"tir.', 'A'),
('fc1e73ab-da8f-493e-bc18-09cbad93e00b', 'Di lêkolîna dîroka Kurd û Kurdistanê de koç çi tê wateyê?', 'Di lêkolîna dîroka Kurd û Kurdistanê de koçberî dikare weke jicîhûwarkirina civakan bê bikaranîn.', 'Di lêkolîna dîroka Kurd û Kurdistanê de koçberî dikare weke jicîhûwarkirina civakan bê bikaranîn.', 'göç, Kürt ve Kürdistan tarihi araştırmalarında toplulukların yer değiştirmesi olarak kullanılabilir.', 'D'),
('fc86cecd-0171-495a-b00e-e62d3cb29fa9', 'Peyva "guh" bi Tirkî tê wateya "göz".', 'Peyva "guh" tê wateya "kulak".', 'Peyva "guh" tê wateya "kulak".', '"guh" kelimesi "kulak" demektir.', 'B'),
('fca101d9-95c4-494f-b7f8-5415282e7080', 'Biryara dîrokî ya ji bo Kongreya 12. a PKK''ê ya di Gulana 2025''an de hat ragihandin çi bû?', 'Li gorî nûçeya Reutersê, Kongreya 12. a PKK’ê biryara bidawîkirina pêkhateya rêxistinî û bidawîkirina şerê çekdarî ragihand.', 'Li gorî nûçeya Reutersê, Kongreya 12. a PKK’ê biryara bidawîkirina pêkhateya rêxistinî û bidawîkirina şerê çekdarî ragihand.', 'Reuters’a göre PKK 12. Kongresi, örgütsel yapının feshi ve silahlı mücadelenin sonlandırılması kararını bildirdi.', 'A'),
('fca9cdd3-1d1c-442f-9a0a-d331b3cc63d6', 'Di Kurmancî de peyva "pênûs" bi Tirkî çi ye?', 'Peyva "pênûs" tê wateya "kalem".', 'Peyva "pênûs" tê wateya "kalem".', '"pênûs" kelimesi "kalem" anlamına gelir.', 'D'),
('fcbd8a77-3029-4674-a2bb-113d4ff62228', 'Di çanda Kurdî de vegotina çîrokan tenê yekeyeke pîvanê ya teknîkî ye.', 'Çîrok ji mijareke teknîkî zêdetir mijareke çandî ye.', 'Çîrok ji mijareke teknîkî zêdetir mijareke çandî ye.', 'masal anlatımı teknik ölçüden çok kültürel bir başlıktır.', 'B'),
('fd3fdce0-4a41-4bdf-a377-abcaef5b417d', 'Di muzîka Kurdî de nota bi çi re têkildar e?', 'Not bi nîşana nivîsandina muzîkê di warê muzîka kurdî de tê girêdan.', 'Not bi nîşana nivîsandina muzîkê di warê muzîka kurdî de tê girêdan.', 'nota, Kürt müziği alanında müziği yazma işareti ile ilişkilidir.', 'A'),
('fdacda11-354c-4d61-b854-3d87508ac589', 'Di derbarê şîn de kîjan rasttir e?', 'Şîn di çanda kurdî de bi qada kevneşopiya devkî ve girêdayî ye.', 'Şîn di çanda kurdî de bi qada kevneşopiya devkî ve girêdayî ye.', 'ağıt, Kürt kültüründe sözlü gelenek alanıyla bağlantılıdır.', 'A'),
('fdc1960b-8e36-4fd6-9acd-8b49c1c26d5f', 'Peyva "bajar" bi Tirkî tê wateya "köy".', '"bajar" tê wateya "şehir"; "gund" tê wateya "köy".', '"bajar" tê wateya "şehir"; "gund" tê wateya "köy".', '"bajar" "şehir" demektir; "gund" ise "köy" anlamına gelir.', 'B'),
('fe0c2600-d683-446f-aa07-2598e55bbc9e', 'Peyva "agir" bi Tirkî tê wateya "toprak".', 'Peyva "agir" tê wateya "ateş".', 'Peyva "agir" tê wateya "ateş".', '"agir" kelimesi "ateş" demektir.', 'B'),
('fe1b90a6-2da7-4857-867d-36bb5a259195', 'Di çanda Kurdî de mêvanperwerî tenê yekeyeke pîvanê ya teknîkî ye.', 'Mêvanperwerî ji pîvanek teknîkî bêtir sernavek çandî ye.', 'Mêvanperwerî ji pîvanek teknîkî bêtir sernavek çandî ye.', 'misafirperverlik teknik ölçüden çok kültürel bir başlıktır.', 'B'),
('fece5e2b-0ebf-4d63-b35f-8f6a1c228222', 'Peyva "hewa" bi Tirkî tê wateya "hava".', 'Wekheviya rast ji bo "hewa" "hava" e.', 'Wekheviya rast ji bo "hewa" "hava" e.', '"hewa" için doğru karşılık "hava"tir.', 'A'),
('ff93d616-78a2-47ea-b757-1bf942d854be', 'Wateya "Jin" bi Tirkî çi ye?', '"Jin" tê wateya mê; "Jin, jiyan, azadî" peyva yekem a sloganê ye.', '"Jin" tê wateya mê; "Jin, jiyan, azadî" peyva yekem a sloganê ye.', '"Jin" kadın demektir; "Jin, jiyan, azadî" sloganının ilk sözcüğüdür.', 'D')
) update questions q set
  prompt=p.prompt, explanation=p.explanation, explanation_ku=p.explanation_ku,
  explanation_tr=p.explanation_tr, quality_version=coalesce(q.quality_version,0)+1, updated_at=now()
from patch p where q.id=p.id::uuid and q.correct_option=p.correct_option and q.is_approved;
commit;
